// radio_golden_24_s1.js — MedGolden Radiology (SK-RADIOLOGY 3rd Edition, vol 24, Set 1) recall MCQs
// Schema: {q,o,a,e} to match platform reader. 1:1 book numbering /*N*/.
// Closing line is a meaningful clincher, never a bare restatement.
if(!window.MM) window.MM={};
window.MM['radio_golden_24_s1']=[
/*1*/ {"q":"Female with milky discharge from nipples. On CT scan, a very small microprolactinoma was found. She also developed amenorrhea and infertility. Cause is?","o":["Dopamine","Pressure effects on FSH and LH cells of pituitary","Decreased gonadotrophin releasing hormone","Increased FSH and LH"],"a":2,"e":"Prolactin inhibits GnRH (gonadotrophin releasing hormone) secretion at the hypothalamic level, leading to reduced FSH and LH, which causes amenorrhea and anovulation. Even a microprolactinoma producing modest prolactin excess is enough to suppress the hypothalamic-pituitary-gonadal axis.<br><br>Key discriminator: GnRH suppression → amenorrhea/anovulation (primary mechanism) | Pituitary pressure (option B) → requires macroadenoma, not micro | Option D → opposite of what happens."},
/*2*/ {"q":"Patients shoe size recently increased and he is having coarse facial features. Which hormone is likely associated with this condition?","o":["ACTH and CRH","TSH and TRH","GHRH and Somatostatin","Prolactin"],"a":2,"e":"Acromegaly results from excess Growth Hormone, which is stimulated by GHRH and normally inhibited by somatostatin. A GH-secreting pituitary adenoma driven by excess GHRH or deficient somatostatin causes soft tissue and bony overgrowth — enlarged hands, feet, jaw, and coarse features.<br><br>Key discriminator: ACTH excess → Cushingoid features | TSH excess → hyperthyroidism | Prolactin excess → galactorrhea/amenorrhea | GHRH/Somatostatin axis → coarse acral growth = acromegaly."},
/*3*/ {"q":"A 45-year-old man with a long history of alcoholism presents with severe epigastric pain, nausea, vomiting, fever and increase in serum amylase. Diagnosis of acute pancreatitis superimposed on chronic pancreatitis was made. In this condition which of the following types of necrosis is most characteristic?","o":["Caseous necrosis","Liquefactive necrosis","Coagulative necrosis","Fat necrosis"],"a":3,"e":"Acute pancreatitis causes release of pancreatic lipases that digest peripancreatic and omental fat, producing chalky-white saponification deposits — the hallmark of fat necrosis. This is distinct from other organ necrosis patterns and is pathognomonic for pancreatic or breast injury.<br><br>Key discriminator: Caseous necrosis → TB/fungi | Liquefactive → brain/abscess | Coagulative → ischemia in solid organs | Fat necrosis → pancreatic lipase release (pathognomonic)."},
/*4*/ {"q":"27 years old woman presented with the complaints of weight gain, amenorrhea and fatigue. Last year, she experienced a complicated delivery requiring 2 units of blood transfusion. She was unable to breastfeed. On examination she has dry skin and hypotension. Which one of the following is the most likely diagnosis?","o":["Conn disease","Sheehan syndrome","Addison syndrome","Nelson syndrome"],"a":1,"e":"Sheehan syndrome results from postpartum pituitary infarction due to obstetric hemorrhage. The pituitary enlarges during pregnancy, making it vulnerable to hypoperfusion. Loss of all anterior pituitary hormones explains inability to lactate (no prolactin), amenorrhea (no FSH/LH), fatigue, dry skin, and hypotension (no TSH, no ACTH).<br><br>Key discriminator: Sheehan → postpartum haemorrhage + failure to lactate + panhypopituitarism | Addison → primary adrenal failure + hyperpigmentation | Conn → aldosterone excess + hypertension."},
/*5*/ {"q":"What primarily regulates coronary blood flow during exercise?","o":["Sympathetic nervous system","Parasympathetic nervous system","Hormones","Local metabolites"],"a":3,"e":"During exercise, increased myocardial oxygen demand leads to local accumulation of metabolites including CO2, H+, adenosine, and lactate, which cause coronary vasodilation — autoregulatory metabolic control dominates coronary circulation. Sympathetic activation plays a secondary role and is partly offset by beta-2 mediated vasodilation.<br><br>Key discriminator: Coronary blood flow → governed by local metabolites (not neural) | Adenosine → key mediator when O2 supply-demand mismatch | Neural control → dominant in skeletal muscle, not coronary bed."},
/*6*/ {"q":"Type of joint between teeth:","o":["Symphysis","Synchondrosis","Gomphosis","Syndesmosis"],"a":2,"e":"A gomphosis is a fibrous joint where a peg-like process fits into a socket — exactly the relationship between a tooth root and the alveolar bone of the jaw, held by the periodontal ligament. It is classified as a fibrous joint with very limited movement.<br><br>Key discriminator: Gomphosis → peg-in-socket (tooth in alveolar bone) | Syndesmosis → bone-to-bone via ligament (tibiofibular) | Synchondrosis → hyaline cartilage (epiphyseal plate) | Symphysis → fibrocartilage (pubic)."},
/*7*/ {"q":"Chlorpromazine most common toxic effect is:","o":["Anxiety","Hallucinations","Dystonia","Constipation"],"a":2,"e":"Chlorpromazine is a typical (first-generation) antipsychotic that blocks D2 receptors in the nigrostriatal pathway, causing extrapyramidal side effects. Acute dystonia — sustained involuntary muscle contractions — is the most common early toxic effect, especially in young males.<br><br>Key discriminator: Chlorpromazine → blocks D2 in nigrostriatal pathway → dystonia (most common toxic effect) | Hallucinations → symptom it treats, not causes | Constipation → occurs but not the most common."},
/*8*/ {"q":"30 yr. old male who was treated for meningitis one month back has complaint of morning headache. What is the likely route of spread of meningitis?","o":["Blood borne transmission","Fecal-oral transmission","Vector-borne transmission","Airborne transmission"],"a":3,"e":"Most bacterial meningitis pathogens (Neisseria meningitidis, Streptococcus pneumoniae) colonize the nasopharynx and spread via respiratory droplets — airborne/droplet transmission — then seed the meninges hematogenously after mucosal invasion. Morning headache post-treatment may suggest post-infectious hydrocephalus or communicating meningitis sequelae.<br><br>Key discriminator: Bacterial meningitis → respiratory droplet spread (primary route) | Fecal-oral → enteroviruses (viral meningitis) | Vector-borne → arboviruses (encephalitis)."},
/*9*/ {"q":"Heart failure cells in the liver are indicative of:","o":["Acute viral hepatitis","Alcoholic liver disease","Hemochromatosis","Chronic passive congestion"],"a":3,"e":"Heart failure cells in the liver are hemosiderin-laden macrophages (Kupffer cells) that accumulate in centrilobular zones due to chronic venous congestion from right-sided heart failure. Prolonged hepatic venous hypertension causes centrilobular necrosis and red cell extravasation, with subsequent hemosiderin deposition.<br><br>Key discriminator: Heart failure cells in liver → chronic passive congestion (right heart failure) | Same cells in lung → pulmonary edema | Both → passive congestion, NOT primary liver pathology."},
/*10*/ {"q":"A patient experiences muscle pain and stiffness ten days after thyroidectomy. What could be the cause?","o":["Hypoparathyroidism","Hypothyroidism","Hypocalcemia","Recurrent laryngeal nerve damage"],"a":2,"e":"Post-thyroidectomy hypocalcemia occurs when the parathyroid glands are inadvertently removed or devascularized. Low calcium leads to increased neuromuscular excitability, manifesting as muscle cramps, tetany, and stiffness. The 10-day timeline fits parathyroid ischemia rather than immediate RLN damage.<br><br>Key discriminator: RLN damage → hoarseness (not cramps) | Hypothyroidism → weeks-months to appear | Hypocalcemia from hypoparathyroidism → the classic post-thyroidectomy muscle symptom cause."},
/*11*/ {"q":"A lady presented with goiter. Iodine deficiency can arise due to which of the following factors?","o":["Low plasma calcium and increased excretion","Genetic mutation","Environmental toxins","Inadequate dietary iodine intake"],"a":3,"e":"Iodine deficiency is the most common worldwide cause of goiter. Insufficient dietary iodine leads to reduced T3/T4 synthesis, compensatory TSH rise, and thyroid gland hyperplasia (goiter) as the gland tries to trap more iodine. Endemic goiter is prevalent in mountainous inland regions far from seafood.<br><br>Key discriminator: Inadequate dietary iodine → most common cause of goiter worldwide | Excessive iodine → paradoxical goiter (Wolff-Chaikoff) | Genetic/environmental → rare secondary causes."},
/*12*/ {"q":"Feature of acid fast bacilli in TB:","o":["Cell wall made of peptidoglycan","Mycolic acids","Capsule","Cords"],"a":1,"e":"Mycobacteria (TB bacilli) are acid-fast due to their unique cell wall rich in mycolic acids — long-chain fatty acids that bind carbol fuchsin dye and resist decolorization with acid-alcohol. This property underlies the Ziehl-Neelsen staining technique used for TB diagnosis.<br><br>Key discriminator: Mycolic acids → exclusive to Mycobacteria + Nocardia → acid-fastness | Peptidoglycan → common to all bacteria | Cords → virulence feature, not the acid-fast basis."},
/*13*/ {"q":"In the context of orthopedic injuries, which type of fracture is frequently associated with older individuals?","o":["Avulsion of anterior iliac spine","Ischial tuberosity fracture","Pubic symphysis fracture","Neck of femur fracture"],"a":3,"e":"Neck of femur (hip) fractures are the classic osteoporotic fracture in elderly individuals, particularly postmenopausal women. Reduced bone density combined with falls makes the femoral neck the most vulnerable site. It accounts for significant morbidity and mortality in the elderly population.<br><br>Key discriminator: Femoral neck fracture → synonymous with elderly osteoporotic fracture | Avulsion (iliac spine/ischial tuberosity) → young athletes/traction | Pubic symphysis → high-energy trauma."},
/*14*/ {"q":"Child while supine with Peanut aspiration will lodge in:","o":["Right upper lobe","Right posterior lobe","Left posterior lobe","Right lower lobe"],"a":3,"e":"In a supine child, the right lower lobe (specifically the superior segment of the right lower lobe) is the most dependent zone, and the right main bronchus is wider and more vertical than the left. Foreign body aspiration therefore preferentially lodges in the right lower lobe when the patient is supine.<br><br>Key discriminator: Supine patient → right lower lobe superior segment is dependent | Upright patient → right lower lobe posterior basal segment | Both positions → right lower lobe is the answer."},
/*15*/ {"q":"Foreign body in left upper lobe. Patient is in supine/standing position. Where does the foreign body lodge?","o":["Inferior lingular segment of left upper lobe","Superior lingular segment of left upper lobe","Left lower lobe superior segment","Left lower lobe basal segment"],"a":0,"e":"The lingula of the left upper lobe is anatomically analogous to the right middle lobe. When a foreign body is in the left upper lobe and the patient is supine or standing, it gravitates to the inferior lingular segment (B4/B5), the most dependent part of the left upper lobe.<br><br>Key discriminator: Lingula → left-sided counterpart of right middle lobe | Inferior lingular segment → most dependent zone of left upper lobe | Foreign body in left upper lobe → lodges at inferior lingular segment."},
/*16*/ {"q":"A patient with alcoholic hepatitis with Mallory bodies. The interwoven structure in Mallory bodies is:","o":["Alpha Amyloid","Alpha syncline","Beta Amyloid","Intermediate filaments"],"a":3,"e":"Mallory-Denk bodies (Mallory bodies) in alcoholic hepatitis are intracytoplasmic eosinophilic inclusions composed of aggregated and ubiquitinated intermediate filaments (specifically cytokeratin 8 and 18). They represent accumulated misfolded cytoskeletal proteins in hepatocytes injured by ethanol.<br><br>Key discriminator: Mallory bodies → intracellular keratin intermediate filaments (CK8/18) | Amyloid → extracellular beta-pleated sheet fibrils | These are opposites — never confuse intracellular vs extracellular."},
/*17*/ {"q":"In the context of orthopedic injuries, which type of fracture is frequently associated with older individuals? (Regarding thermal receptors, which type of adapter changes are due to long-term memory changes of Hippocampus)","o":["Adpat Quickly To Change In","Large Receptive Field","Delta Fibers","Temperature"],"a":0,"e":"Thermal receptors that adapt quickly to temperature changes are rapidly adapting receptors. These detect the onset and offset of thermal stimuli but not steady-state temperature. They respond to dynamic changes rather than maintained temperature, providing the sensation of warming or cooling.<br><br>Key discriminator: Rapidly adapting receptors → signal change in temperature (phasic) | Slowly adapting → encode sustained/maintained stimuli (tonic) | 'Adapt quickly' → phasic receptors."},
/*18*/ {"q":"Hypercalcemia and hypokalemia affect on heart:","o":["Systolic arrest","Diastolic arrest","Both arrests","No significant effect on heart"],"a":0,"e":"Hypercalcemia causes systolic cardiac arrest by stabilizing the cardiac membrane at a depolarized state, increasing contractility to the point of sustained systolic contraction. Hyperkalemia causes diastolic arrest; hypocalcemia causes diastolic arrest. Hypokalemia causes arrhythmias but the dominant effect here with hypercalcemia is systolic arrest.<br><br>Key discriminator: Hypercalcemia → systolic arrest (excess Ca locks heart in contraction) | Hyperkalemia → diastolic arrest | Memory: Ca = contraction, K = relaxation."},
/*19*/ {"q":"After trauma to scaphoid bone, patient having bleed and pain. Which structure is damaged?","o":["Radial nerve","Ulnar nerve","Median nerve","Radial artery"],"a":3,"e":"The radial artery crosses the anatomical snuffbox, directly overlying the scaphoid bone. Scaphoid fractures (the most common carpal fracture) can injure the radial artery at this point, and avascular necrosis of the scaphoid occurs because its blood supply enters distally and traverses the bone retrograde.<br><br>Key discriminator: Anatomical snuffbox tenderness → scaphoid fracture | Radial artery → crosses snuffbox over scaphoid = vascular structure at risk | Radial nerve → sensation on dorsum of hand only."},
/*20*/ {"q":"The volume of amniotic fluid at term is:","o":["200 ml","400 ml","600 ml","800 ml"],"a":3,"e":"Amniotic fluid volume peaks at approximately 800 ml at term (37-40 weeks). It is produced by fetal urine output, fetal lung fluid, and placental transfer. Polyhydramnios is defined as greater than 2000 ml; oligohydramnios as less than 300 ml at term.<br><br>Key discriminator: Amniotic fluid at term → ~800 ml (peaks near 37-40 weeks) | 600 ml → mid-pregnancy value, not term | Polyhydramnios → >2000 ml | Oligohydramnios → <300 ml at term."},
/*21*/ {"q":"Structure prone to damage in quadrangular space?","o":["Anterior circumflex humeral artery","Brachial plexus","Branch of axillary nerve","Subclavian artery"],"a":2,"e":"The quadrangular space is bounded by teres minor, teres major, long head of triceps, and the surgical neck of humerus. It transmits the axillary nerve and posterior circumflex humeral artery. Compression or injury in this space damages the axillary nerve, causing deltoid weakness and loss of sensation over the regimental badge area.<br><br>Key discriminator: Quadrangular space → transmits axillary nerve + posterior circumflex humeral artery | Triangular space → circumflex scapular artery | Quadrangular space compression → deltoid atrophy + regimental badge numbness."},
/*22*/ {"q":"In cubital fossa most medial structure is:","o":["Median nerve","Bifurcation of brachial artery","Bicep tendon","Radial nerve"],"a":0,"e":"The cubital fossa contents from medial to lateral follow the mnemonic 'Really Need Beer To Be At My Nicest': from medial — Median nerve, Brachial Artery, Biceps tendon, Radial nerve. The median nerve is the most medial structure in the cubital fossa.<br><br>Key discriminator: Cubital fossa (medial to lateral): Median nerve → Brachial artery → Biceps tendon → Radial nerve | Median nerve = most medial | Radial nerve = most lateral."},
/*23*/ {"q":"Hoarseness of voice develops in a patient following thyroidectomy. The nerve injured in vicinity of the inferior thyroid artery is:","o":["Internal laryngeal nerve","External laryngeal nerve","Accessory nerve","Recurrent laryngeal nerve"],"a":3,"e":"The recurrent laryngeal nerve runs in the tracheoesophageal groove and is intimately related to the inferior thyroid artery, where it is most vulnerable during thyroidectomy. Injury causes ipsilateral vocal cord paralysis manifesting as hoarseness (unilateral) or aphonia/stridor (bilateral).<br><br>Key discriminator: RLN injury → hoarseness (posterior cricoarytenoid paralysis) | ELN injury → cricothyroid weakness, voice fatigue, loss of high pitch (NO hoarseness) | Hoarseness specifically = RLN."},
/*24*/ {"q":"Superior thyroid artery is related to which nerve?","o":["Inferior laryngeal nerve","Internal laryngeal nerve","Recurrent laryngeal nerve","External laryngeal nerve"],"a":3,"e":"The superior thyroid artery is closely related to the external laryngeal nerve (ELN), which runs with it before the artery enters the thyroid gland. Ligation of the superior thyroid artery high up risks injuring the ELN, causing cricothyroid muscle weakness and altered voice quality (loss of high-pitched phonation).<br><br>Key discriminator: Superior thyroid artery → related to ELN (external laryngeal nerve) | Inferior thyroid artery → related to RLN (recurrent laryngeal nerve) | Ligate superior pedicle carefully → preserve ELN."},
/*25*/ {"q":"During quiet inspiration, what is the primary muscle responsible for increasing the volume of the thoracic cavity?","o":["External intercostal muscles","Internal intercostal muscles","Sternocleidomastoid muscle","Diaphragm"],"a":3,"e":"The diaphragm is responsible for approximately 75% of the tidal volume during quiet breathing. Its contraction increases the vertical dimension of the thoracic cavity by descending, generating the negative intrathoracic pressure that drives airflow. External intercostals contribute the remaining 25%.<br><br>Key discriminator: Quiet breathing → diaphragm provides ~75% of tidal volume | External intercostals → remaining ~25% | Accessory muscles (SCM, scalenes) → only during forced inspiration or distress."},
/*26*/ {"q":"Clara cells are present in:","o":["Respiratory bronchioles","Intralobular bronchioles","Terminal bronchioles","Trachea"],"a":2,"e":"Clara cells (Club cells) are non-ciliated secretory cells found predominantly in the terminal bronchioles. They produce surfactant-like proteins, detoxify inhaled substances, and serve as progenitor cells for bronchiolar epithelium. They are absent in larger airways.<br><br>Key discriminator: Terminal bronchioles → Clara/Club cells (non-ciliated secretory) | Bronchi/trachea → goblet cells dominant | Clara cells = terminal bronchioles = last conducting airway."},
/*27*/ {"q":"A 50-year-old female experiences irregular menstrual periods. What is the most likely cause of this condition?","o":["Pregnancy","Menopause","Polycystic Ovary Syndrome (PCOS)","Hyperprolactinemia"],"a":1,"e":"In a 50-year-old woman, irregular periods are most likely due to perimenopause/menopause — the natural decline in ovarian follicular reserve leads to erratic estrogen production, anovulatory cycles, and irregular menstruation. The average age of menopause is 51 years.<br><br>Key discriminator: Age 50 + irregular periods → perimenopause/menopause (most likely) | PCOS → reproductive years 20s-30s + hyperandrogenism | Age is the key discriminator here."},
/*28*/ {"q":"Pancreatic magna is branch of:","o":["Splenic artery","Gastric artery","Hepatic artery","Superior mesenteric artery"],"a":0,"e":"The arteria pancreatica magna (great pancreatic artery) is the largest branch to the pancreas and arises from the splenic artery. It supplies the body and tail of the pancreas. The splenic artery runs along the superior border of the pancreas, giving off multiple pancreatic branches.<br><br>Key discriminator: Arteria pancreatica magna → branch of splenic artery (largest pancreatic branch) | Superior pancreaticoduodenal arteries → from gastroduodenal (celiac territory) | Splenic artery → supplies body/tail of pancreas."},
/*29*/ {"q":"A Tailor had TB infection transmitted to two of his family members. Mode of spread of this condition is?","o":["Aerosolized air droplets","Blood transfusion","Sexual contact","Needle sticks injury"],"a":0,"e":"Mycobacterium tuberculosis spreads almost exclusively via aerosolized respiratory droplets containing droplet nuclei (1-5 microns) that remain suspended in air. Close prolonged contact in enclosed spaces — as in a household — is the classic transmission scenario.<br><br>Key discriminator: TB spread → droplet nuclei via aerosol (exclusive primary route) | NOT blood transfusion, needle stick, or sexual contact | Distinguishes TB from HIV/HBV (blood-borne) and influenza (larger droplets)."},
/*30*/ {"q":"Patient presents with breathlessness, pH 7.35, PCO2 60, O2 75 and HCO3 18. Which acid base disorder is this?","o":["Respiratory acidosis","Uncompensated metabolic acidosis","Metabolic alkalosis","Metabolic acidosis"],"a":0,"e":"pH 7.35 (low-normal), PCO2 60 (elevated), HCO3 18 (low-normal) indicates primary respiratory acidosis with partial metabolic compensation. The elevated PCO2 is the primary disturbance; the relatively normal pH shows the kidneys have partially compensated by retaining bicarbonate.<br><br>Key discriminator: High PCO2 + low-normal pH + normal-low HCO3 → respiratory acidosis with partial metabolic compensation | Metabolic acidosis → primary HCO3 fall + low PCO2 (respiratory compensation) | PCO2 high = respiratory problem."},
/*31*/ {"q":"In a 60-year-old patient, which medical condition is likely to present with a decreased reticulocyte count due to impaired erythropoiesis?","o":["Iron-deficiency anemia","Metabolic alkalosis","Chronic renal failure","Hyperthyroidism"],"a":2,"e":"Chronic renal failure causes decreased production of erythropoietin (EPO) from damaged kidneys, leading to reduced stimulation of erythroid precursors in the bone marrow. This results in a normocytic normochromic anemia with low reticulocyte count — a hypoproliferative anemia.<br><br>Key discriminator: Chronic renal failure → low EPO → low reticulocytes + normocytic anaemia | Iron deficiency → low reticulocytes but microcytic | 'Impaired erythropoiesis' clue → EPO deficiency from renal failure."},
/*32*/ {"q":"A patient with severe headache, neck stiffness, blood-stained CSF on lumbar puncture, and raised ICP. Diagnosis is:","o":["Extradural hematoma","Subdural hematoma","Cerebral hematoma","Subarachnoid hemorrhage"],"a":3,"e":"Sudden severe headache ('thunderclap'), neck stiffness (meningism), and bloody/xanthochromic CSF on lumbar puncture are the classic triad of subarachnoid hemorrhage (SAH). Raised ICP is expected due to blood in the subarachnoid space disrupting CSF reabsorption.<br><br>Key discriminator: Bloody/xanthochromic CSF + thunderclap headache + neck stiffness → SAH | Clear CSF → extradural/subdural (no CSF blood) | LP finding = defining differentiator for SAH."},
/*33*/ {"q":"Barr body is associated with which cell?","o":["Neutrophils","Lymphocytes","Eosinophils","Mast cells"],"a":0,"e":"Barr bodies (condensed inactive X chromosomes) are visible as the 'drumstick' appendage on the nuclear lobe of neutrophils in females. This is the most accessible cell type used historically to determine chromosomal sex from peripheral blood smears.<br><br>Key discriminator: Barr body in neutrophils → seen as drumstick appendage on nuclear lobe | Present in all female somatic cells but most easily visualised in neutrophils | Lymphocytes → require special preparation."},
/*34*/ {"q":"What is the recommended daily protein requirement expressed as a percentage of daily caloric intake?","o":["5%","10-15%","25%","50%"],"a":1,"e":"The recommended daily protein intake for average adults is 10-15% of total caloric intake, corresponding to approximately 0.8 g/kg/day. Athletes and critically ill patients may need 1.2-2.0 g/kg/day. Protein provides 4 kcal/g.<br><br>Key discriminator: Protein → 10-15% of daily calories (standard recommendation) | Carbohydrates → 50-60% | Fats → 25-35% | 25% or 50% protein → hyperprotein therapeutic diets only."},
/*35*/ {"q":"Following structure which will compress head of Pancreas:","o":["Hepatic duct","IVC","Common bile duct","Portal vein"],"a":2,"e":"The common bile duct (CBD) runs in the posterior groove of the head of the pancreas before entering the duodenum at the ampulla of Vater. Pancreatic head carcinoma or pancreatitis compresses the CBD, causing obstructive jaundice — painless jaundice in pancreatic cancer is due to this anatomical relationship.<br><br>Key discriminator: CBD → embedded in posterior groove of pancreatic head | Pancreatic head mass → compresses CBD → obstructive jaundice | IVC + portal vein → posterior to pancreas, not in groove."},
/*36*/ {"q":"Peau d'orange appearance of breasts occurs in malignancy of:","o":["Suspensory ligament of breast","Longitudinal ligament of breast","Lymphatics of breast","Lobules of breast"],"a":2,"e":"Peau d'orange (orange peel skin) occurs when breast malignancy obstructs the dermal lymphatics, causing lymphedema of the overlying skin. The skin dimples appear at the openings of sweat gland ducts, which are tethered to the dermis, while the surrounding skin swells — creating the orange peel texture.<br><br>Key discriminator: Peau d'orange → dermal lymphatic obstruction → skin oedema with fixed dimples | Cooper's ligament tethering → skin dimpling (different sign) | Peau d'orange = sign of advanced/inflammatory breast cancer."},
/*37*/ {"q":"Respiratory zone where gaseous exchange occurs beyond?","o":["Terminal bronchioles to alveoli","Respiratory bronchioles to alveoli","Longitudinal ligament of breast","Lymphatics of breast"],"a":1,"e":"The respiratory zone begins at the respiratory bronchioles and extends to the alveolar ducts and alveoli — this is where gas exchange actually occurs. The conducting zone ends at the terminal bronchioles (anatomical dead space). Respiratory bronchioles have alveoli opening directly into their walls.<br><br>Key discriminator: Terminal bronchioles → end of conducting zone (no gas exchange) | Respiratory bronchioles → start of respiratory zone (alveoli appear in walls) | Junction = the conducting-to-respiratory zone transition point."},
/*38*/ {"q":"Patient with nephrotic syndrome. Which structure in GBM plays a major role in perm-selectivity for proteins?","o":["Lamina rara externa","Lamina densa","Lamina rara interna","Visceral epithelial layer"],"a":1,"e":"The lamina densa of the glomerular basement membrane (GBM) is the central dense layer rich in type IV collagen and provides the primary size-selective barrier. However, the lamina rara interna and externa contain heparan sulfate proteoglycans providing charge selectivity. In nephrotic syndrome, loss of charge selectivity allows protein loss.<br><br>Key discriminator: Lamina densa (type IV collagen) → size selectivity | Laminae rarae (heparan sulphate) → charge selectivity | Nephrotic syndrome → charge barrier loss → protein leak."},
/*39*/ {"q":"A person is having history of smoking and drinking from many years. On Endoscopy there is a mass in middle third of esophagus. What could it likely be?","o":["BCC","Adenocarcinoma","Squamous cell carcinoma","Malignant melanoma"],"a":2,"e":"Squamous cell carcinoma (SCC) predominates in the middle third of the esophagus and is strongly associated with smoking and alcohol, which act synergistically as carcinogens on the squamous epithelium. The middle and upper thirds of the esophagus are lined by stratified squamous epithelium.<br><br>Key discriminator: Middle third oesophagus + smoking + alcohol → SCC (squamous epithelium) | Lower third/GEJ + GERD → adenocarcinoma (from Barrett's metaplasia) | Location + risk factors = key pattern."},
/*40*/ {"q":"Pain of indirect inguinal hernia is due to compression of which nerve in inguinal canal?","o":["Ilioinguinal","Femoral","Obturator","Iliohypogastric"],"a":0,"e":"The ilioinguinal nerve traverses the inguinal canal and exits through the superficial inguinal ring. It provides sensory innervation to the medial thigh, the scrotum/labia majora, and the root of the penis/mons pubis. Compression by an indirect inguinal hernia causes pain and paresthesia in these distributions.<br><br>Key discriminator: Ilioinguinal nerve → runs within inguinal canal → compressed by indirect inguinal hernia | Genitofemoral genital branch → also enters canal but secondary | Femoral nerve → lateral to canal, not within."},
/*41*/ {"q":"PCT absorb 45-50% which of following:","o":["Glucose","HCO3","Urea","Water"],"a":3,"e":"The proximal convoluted tubule (PCT) reabsorbs approximately 65-70% of filtered water isotonically along with sodium. However, the question likely refers to urea reabsorption — approximately 40-50% of filtered urea is passively reabsorbed in the PCT. Water reabsorption in PCT is 65-70%, not 45-50%.<br><br>Key discriminator: PCT reabsorption: Glucose → 100% | HCO3 → 85-90% | Urea → 40-50% (passive) | The 45-50% figure → matches urea specifically."},
/*42*/ {"q":"Anterior 2/3rd general sensation carried by:","o":["Facial nerve","Glossopharyngeal nerve","Vagus nerve","Trigeminal nerve"],"a":3,"e":"General somatic sensation (touch, pain, temperature) from the anterior two-thirds of the tongue is carried by the lingual nerve, a branch of the mandibular division (V3) of the trigeminal nerve. Special taste sensation from the same region is carried by the chorda tympani (branch of CN VII).<br><br>Key discriminator: Anterior 2/3 tongue: General sensation → trigeminal (lingual nerve V3) | Taste → facial (chorda tympani CN VII) | Posterior 1/3: Both general sensation + taste → glossopharyngeal (CN IX)."},
/*43*/ {"q":"On immunofluorescence, which nephropathy shows increased mesangial IgA deposition?","o":["Membranous nephropathy","IgA nephropathy (Berger's disease)","Minimal change disease","Focal segmental glomerulosclerosis"],"a":1,"e":"IgA nephropathy (Berger's disease) is characterized by mesangial IgA deposits on immunofluorescence, appearing as granular mesangial staining. It typically presents with episodic gross hematuria following upper respiratory infections in young adults.<br><br>Key discriminator: IgA nephropathy → mesangial IgA deposits (granular mesangial pattern on IF) | Membranous nephropathy → IgG subepithelial deposits | Lupus nephritis → full-house immunofluorescence."},
/*44*/ {"q":"Secretory granules of ADH and oxytocin are stored in:","o":["Astrocytes","Pituicytes","Kupffer cells","Nerve endings (Herring bodies)"],"a":3,"e":"The posterior pituitary (neurohypophysis) stores and releases ADH (vasopressin) and oxytocin, which are produced in hypothalamic nuclei (supraoptic and paraventricular) and transported down axons to be stored in nerve endings (Herring bodies) in the posterior pituitary.<br><br>Key discriminator: ADH + oxytocin → stored in axon terminals (Herring bodies) in posterior pituitary | Pituicytes → glial support cells only, do NOT store hormones | Hypothalamic neurons = production site; nerve endings = storage site."},
/*45*/ {"q":"Epiblast is formed by: Extraembryonic mesoderm formed by:","o":["Extraembryonic coelom: Hypoblast","Epiblast","Lateral plate mesoderm","Intermediate mesoderm"],"a":1,"e":"The extraembryonic mesoderm is derived from the epiblast. During gastrulation, epiblast cells migrate through the primitive streak to form intraembryonic mesoderm, and some epiblast-derived cells migrate laterally to contribute to extraembryonic mesoderm lining the chorionic cavity.<br><br>Key discriminator: Extraembryonic mesoderm → from epiblast | Hypoblast → forms primary yolk sac + extraembryonic endoderm | Epiblast → gives rise to all three germ layers + extraembryonic mesoderm."},
/*46*/ {"q":"In Sickle cell anemia child has low hb which hemoglobin will be seen in his blood?","o":["HBF","HBA","HBA2","HBS"],"a":0,"e":"In infants and young children with sickle cell disease, fetal hemoglobin (HbF) is present in significant amounts and persists longer than in normal children. HbF does not sickle because gamma chains replace beta chains, providing natural protection. Agents like hydroxyurea increase HbF levels therapeutically.<br><br>Key discriminator: HbF → protects against sickling (gamma chains replace beta chains) | HbS → sickle haemoglobin (adult, beta-globin mutation) | HbA2 → elevated in beta thalassemia | Young child with SCD → HbF + HbS coexist."},
/*47*/ {"q":"Which muscle is innervated by the facial nerve (CN VII)?","o":["Buccinator","Masseter","Temporalis","Medial pterygoid"],"a":0,"e":"The buccinator muscle is innervated by the buccal branch of the facial nerve (CN VII). It is the only muscle of mastication area innervated by CN VII rather than the trigeminal nerve. The salpingopharyngeus is innervated by the vagus nerve via the pharyngeal plexus.<br><br>Key discriminator: Buccinator → innervated by CN VII (facial expression muscle, not mastication) | Muscles of mastication → CN V3 (masseter, temporalis, pterygoids) | Buccinator lies in cheek but = CN VII muscle."},
/*48*/ {"q":"The floor of the acetabular fossa is formed by contributions from:","o":["Pubis and ischium only","Ilium and ischium only","Pubis and ilium only","Pubis, ilium and ischium"],"a":3,"e":"The floor of the acetabular fossa (acetabulum) is formed by contributions from all three bones of the os coxa: the pubis, ilium, and ischium. The acetabulum itself is formed at the triradiate cartilage junction of these three bones, which fuse at approximately 16-18 years of age.<br><br>Key discriminator: Acetabulum → formed by all three: pubis + ilium + ischium | No single bone forms it alone | They meet at the triradiate cartilage (fuses ~16-18 years)."},
/*49*/ {"q":"Sarcomere lies between:","o":["Two Z-Lines","Two A-Lines","Two Y-Lines","Two I-Lines"],"a":0,"e":"A sarcomere is the functional contractile unit of skeletal muscle, defined as the segment between two consecutive Z-lines (Z-discs). It contains one full A-band (thick myosin filaments) flanked by two half I-bands (thin actin filaments). Z-lines anchor the actin filaments.<br><br>Key discriminator: Sarcomere → Z-line to Z-line | A-band → thick myosin (+ overlapping actin) | I-band → thin actin only | M-line → centre of A-band | Memory: Z to Z = sarcomere."},
/*50*/ {"q":"A patient having abdominal pain upon investigation necrosed distal 3rd of duodenum. Which artery is involved?","o":["Superior pancreaticoduodenal","Celiac","Aorta","Inferior pancreaticoduodenal"],"a":3,"e":"The distal duodenum (3rd and 4th parts) is supplied by the inferior pancreaticoduodenal artery, a branch of the superior mesenteric artery (SMA). The proximal duodenum (1st and 2nd parts) is supplied by the superior pancreaticoduodenal artery from the gastroduodenal artery (branch of celiac).<br><br>Key discriminator: Distal duodenum (3rd/4th parts) → supplied by inferior pancreaticoduodenal artery (SMA branch) | Proximal duodenum (1st/2nd) → superior pancreaticoduodenal (gastroduodenal/celiac) | Watershed → junction of 2nd and 3rd parts."}
,
/*51*/ {"q":"In dialysis patient, clinical way of monitoring of GFR is:","o":["Inulin Clearance","Creatinine Clearance","BUN","Urea"],"a":1,"e":"Creatinine clearance is the standard clinical method for estimating GFR. Inulin clearance is the gold standard but is only used in research. Creatinine is endogenously produced at a steady rate, freely filtered, and minimally secreted, making its clearance a reliable GFR surrogate.<br><br>Key discriminator: Creatinine clearance → clinical standard for GFR monitoring | Inulin clearance → gold standard (research only, impractical) | BUN/urea → affected by non-renal factors, unreliable alone."},
/*52*/ {"q":"In dialysis patient, what is the accurate way of monitoring GFR?","o":["Inulin Clearance","Creatinine Clearance","BUN","K clearance"],"a":0,"e":"Inulin clearance is the gold standard for accurate GFR measurement because inulin is freely filtered at the glomerulus and is neither secreted nor reabsorbed by the tubules. Its urinary clearance therefore equals GFR exactly.<br><br>Key discriminator: Inulin clearance → gold standard (accurate): freely filtered, NOT secreted or reabsorbed → clearance = GFR exactly | Creatinine → slightly overestimates (tubular secretion) | 'Accurate' = inulin."},
/*53*/ {"q":"Hepatic vein drains into:","o":["Portal vein","Superior mesenteric vein","Inferior vena cava","Splenic vein"],"a":2,"e":"The hepatic veins (right, middle, left) drain venous blood from the liver directly into the inferior vena cava (IVC) just below the diaphragm. This anatomy is critical in Budd-Chiari syndrome, where hepatic vein thrombosis causes hepatic congestion.<br><br>Key discriminator: Hepatic veins → carry blood FROM liver TO IVC | Portal vein → carries blood TO liver | Afferent = portal; efferent = hepatic veins."},
/*54*/ {"q":"The ascent of horseshoe kidney is prevented by:","o":["Left renal vein","Superior mesenteric artery","Inferior mesenteric artery","Aortic bifurcation"],"a":2,"e":"During fetal ascent from the pelvis, the isthmus of a horseshoe kidney is arrested by the inferior mesenteric artery (IMA), which arises at L3. The fused kidney cannot pass above this vessel, leaving it malpositioned in the lower abdomen or pelvis.<br><br>Key discriminator: Horseshoe kidney ascent → arrested by IMA (inferior mesenteric artery) at L3 | SMA → commonly confused but IMA is correct | IMA at L3 = mechanical barrier below normal final renal position."},
/*55*/ {"q":"Horseshoe kidney is associated with which of the following conditions?","o":["Pyelonephritis","Polycystic kidney disease","Renal cell carcinoma","Turner syndrome"],"a":3,"e":"Horseshoe kidney is the most common renal fusion anomaly and is classically associated with Turner syndrome (45,XO). It is also associated with Wilms tumor, hydronephrosis, and vesicoureteric reflux. Turner syndrome patients should be screened for this renal anomaly.<br><br>Key discriminator: Horseshoe kidney → classically associated with Turner syndrome (45,XO) | Also associated with → Wilms tumour, hydronephrosis, VUR | ADPKD → separate cystic disease, unrelated."},
/*56*/ {"q":"History of trauma to scrotum with anterior abdominal swelling due to rupture of:","o":["Prostatic urethra","Bulbar (spongy) urethra","Membranous urethra","Ureter"],"a":1,"e":"Rupture of the bulbar urethra allows urine to extravasate deep to Colles fascia, which is continuous with Scarpa's fascia of the anterior abdominal wall. This fascial continuity directs urine upward into the scrotum and anterior abdominal wall, causing the characteristic swelling pattern.<br><br>Key discriminator: Bulbar urethra rupture → urine tracks via Colles fascia → Scarpa fascia → scrotum + anterior abdominal wall | Prostatic urethra rupture → extravasation into pelvis | Fascial plane = determines where urine tracks."},
/*57*/ {"q":"Person is in progressive shock and compensatory mechanisms have failed. What type of acid-base imbalance will be present?","o":["Metabolic acidosis only","Metabolic alkalosis with respiratory alkalosis","Metabolic acidosis with respiratory alkalosis","Metabolic alkalosis with respiratory acidosis"],"a":2,"e":"In progressive decompensated shock, tissue hypoperfusion produces lactic acidosis (metabolic acidosis). The body compensates by hyperventilating to lower PCO2, creating a concurrent respiratory alkalosis. This mixed pattern — metabolic acidosis plus respiratory alkalosis — is the hallmark of decompensating shock before full respiratory failure sets in.<br><br>Key discriminator: Decompensated shock: Metabolic acidosis (lactic) + Respiratory alkalosis (hyperventilation compensation) = mixed picture | Early shock → pure metabolic acidosis | Late failure → both metabolic + respiratory acidosis."},
/*58*/ {"q":"Independent of other causes, most common cause of thrombosis is:","o":["Hypertension","Diabetes mellitus","Trauma","Prolonged immobilization"],"a":3,"e":"Prolonged immobilization is the most common independent cause of venous thrombosis. It produces venous stasis — the first element of Virchow's triad — leading to DVT particularly in the lower limbs. It accounts for the high thrombosis risk in hospitalized, post-surgical, and long-haul travel patients.<br><br>Key discriminator: Immobilisation → venous stasis (Virchow's triad component 1) → most common independent cause of DVT | DM/HTN → endothelial damage (component 3) | Trauma → all three components but less ubiquitous."},
/*59*/ {"q":"Most aggressive skin tumor is:","o":["Squamous cell carcinoma","Malignant melanoma","Basal cell carcinoma","Intraepithelial carcinoma"],"a":1,"e":"Malignant melanoma is the most aggressive skin tumor with a high rate of lymphatic and hematogenous metastasis even from thin primary lesions. Its five-year survival drops precipitously with increasing Breslow thickness and nodal involvement.<br><br>Key discriminator: Melanoma → most aggressive (early systemic metastasis, immune evasion) | SCC → metastasises more than BCC but far less than melanoma | BCC → locally destructive, almost never metastasises."},
/*60*/ {"q":"If a substance has filtration rate greater than its secretion, what will happen?","o":["Tubular reabsorption must occur","Clearance will exceed GFR","Clearance will equal GFR","Clearance will be less than GFR"],"a":0,"e":"If a substance is filtered more than it is secreted, and it still appears in urine at a concentration suggesting net removal from plasma, then reabsorption must also be occurring. Net handling depends on the balance of filtration, secretion, and reabsorption — if filtration exceeds secretion alone, tubular reabsorption is implied to account for the net excretion rate.<br><br>Key discriminator: Clearance > GFR → net secretion | Clearance < GFR → net reabsorption | Clearance = GFR → no tubular handling (inulin) | More filtration than secretion alone → reabsorption must also be occurring."},
/*61*/ {"q":"Calcitonin is a tumor marker of:","o":["Thyroid CA","Ovarian CA","Colonic CA","Breast CA"],"a":0,"e":"Calcitonin is secreted by the parafollicular C-cells of the thyroid gland and is the specific tumor marker for medullary thyroid carcinoma (MTC). Elevated serum calcitonin is diagnostic and is used for post-operative surveillance and screening of MEN 2A/2B family members.<br><br>Key discriminator: Calcitonin → medullary thyroid carcinoma (C-cell origin) | Thyroglobulin → papillary/follicular thyroid cancer | CA-125 → ovarian | CEA → colorectal | CA 15-3 → breast."},
/*62*/ {"q":"Fenestrated capillaries found mostly in:","o":["Skin","Spleen","Brain","Kidney"],"a":3,"e":"Fenestrated capillaries with transcellular pores (with or without diaphragms) are found in organs requiring rapid filtration: kidney glomeruli and peritubular capillaries, intestinal villi, endocrine glands, and choroid plexus. The glomerular capillaries are fenestrated without diaphragms to allow ultrafiltration.<br><br>Key discriminator: Fenestrated capillaries → kidney, endocrine glands, intestinal villi | Sinusoidal (discontinuous) → liver, spleen, bone marrow | Continuous (tight) → brain, lung, skin | Kidney = classic fenestrated capillary answer."},
/*63*/ {"q":"In ECG, complete ventricular depolarization is represented by:","o":["P wave","QRS complex","ST segment","T wave"],"a":1,"e":"The QRS complex represents the electrical depolarization of both ventricles — the rapid spread of the action potential through the ventricular myocardium via the His-Purkinje system. This triggers ventricular contraction (systole).<br><br>Key discriminator: P wave → atrial depolarisation | QRS → ventricular depolarisation | T wave → ventricular repolarisation | ST segment → plateau phase of ventricular action potential."},
/*64*/ {"q":"A patient has bleeding problem. Lab: PT prolonged 60 sec, APTT prolonged 12 min, Bleeding time 12 min. Defect in which pathway?","o":["Extrinsic pathway","Intrinsic pathway","Platelet function","Common pathway"],"a":3,"e":"Both PT (extrinsic + common) and APTT (intrinsic + common) are prolonged simultaneously. This pattern indicates a defect in the common pathway (Factor X, V, II/prothrombin, or fibrinogen), which is shared by both the extrinsic and intrinsic systems. DIC also produces this pattern with additional thrombocytopenia.<br><br>Key discriminator: PT prolonged only → Factor VII (extrinsic) | APTT prolonged only → Factors VIII/IX/XI/XII (intrinsic) | Both PT + APTT prolonged → common pathway (X, V, II, fibrinogen) or DIC."},
/*65*/ {"q":"ALT and AST raised, recent history of travel to remote area. The causing agent is:","o":["Hepatitis A","Hepatitis B","Hepatitis C","Hepatitis D"],"a":0,"e":"Hepatitis A virus (HAV) spreads via the fecal-oral route and is associated with travel to areas with poor sanitation. It causes acute self-limiting hepatitis with elevated transaminases (ALT > AST). There is no chronic phase and full recovery occurs in the vast majority of cases.<br><br>Key discriminator: Travel + fecal-oral + acute hepatitis → Hepatitis A | Parenteral/sexual → Hep B and C | Hep E → also fecal-oral but dangerous in pregnancy | Travel history = Hep A clue."},
/*66*/ {"q":"Most common heart sound produced in:","o":["Rapid ventricular filling","Slow ventricular filling","Isovolumetric contraction","Isovolumetric relaxation"],"a":0,"e":"The third heart sound (S3) is generated during the rapid ventricular filling phase in early diastole, when blood rushing in from the atrium decelerates abruptly against the ventricular wall. In adults over 40, S3 is pathological and indicates volume overload or heart failure.<br><br>Key discriminator: S1 → AV valve closure (start of systole) | S2 → semilunar valve closure (end of systole) | S3 → rapid filling early diastole | S4 → atrial kick against stiff ventricle (late diastole)."},
/*67*/ {"q":"LAD associated vein is:","o":["Small cardiac vein","Great cardiac vein","Middle cardiac vein","Coronary sinus"],"a":1,"e":"The great cardiac vein runs alongside the left anterior descending (LAD) artery in the anterior interventricular groove, then curves around the left side to join the coronary sinus. It is the largest cardiac vein and drains the territory supplied by the LAD.<br><br>Key discriminator: Great cardiac vein → anterior interventricular groove with LAD | Middle cardiac vein → posterior interventricular groove with PDA | Small cardiac vein → right coronary groove with RCA."},
/*68*/ {"q":"Left an heart sound produced during:","o":["Rapid filling","Isovolumetric contraction","Isovolumetric relaxation","Slow filling"],"a":1,"e":"The first heart sound (S1) is produced at the onset of ventricular systole during isovolumetric contraction, when the mitral and tricuspid valves snap shut. The sudden tension of the closing AV valves and the associated blood column vibration generates the 'lub' component of S1.<br><br>Key discriminator: S1 → isovolumetric contraction (AV valve closure) | S2 → isovolumetric relaxation (semilunar valve closure) | S3 → rapid filling | S4 → atrial contraction."},
/*69*/ {"q":"Which of the following is part of triple screening?","o":["Estradiol","Estrone","Estriol","Progesterone"],"a":2,"e":"Second trimester triple screen measures maternal serum AFP, hCG, and unconjugated estriol (uE3). Estriol is produced by the fetoplacental unit (fetal adrenal DHEAS converted by placenta). Low uE3 is associated with Down syndrome and trisomy 18.<br><br>Key discriminator: Triple screen measures: AFP + hCG + unconjugated estriol (uE3) | uE3 (estriol) → fetoplacental unit marker | Low uE3 → Down syndrome / trisomy 18 | NOT estradiol or estrone."},
/*70*/ {"q":"Estradiol in post-menopausal state gets thicker in:","o":["Fundus","Antrum","Cardiac region","Pylorus"],"a":0,"e":"In post-menopausal women, the endometrium at the fundus of the uterus becomes the site of concern for pathological thickening. Estrone (from peripheral adipose conversion of androstenedione) is the dominant post-menopausal estrogen and can stimulate endometrial proliferation at the fundus, raising the risk of endometrial carcinoma.<br><br>Key discriminator: Post-menopausal dominant oestrogen → oestrone (from adipose conversion of androstenedione) | Thickest endometrium → fundus | Fundal thickening → monitored by transvaginal ultrasound for endometrial carcinoma risk."},
/*71*/ {"q":"Study of affected and non-affected is:","o":["Cohort study","Case control","Cross sectional","Prospective study"],"a":1,"e":"A case-control study compares individuals with a disease (cases/affected) to those without (controls/non-affected) and looks backward to identify exposure differences. It is ideal for rare diseases and generates odds ratios.<br><br>Key discriminator: Case-control → affected vs non-affected looked backward (odds ratio) | Cohort → exposed vs non-exposed followed forward | Cross-sectional → snapshot at one time point | 'Affected vs non-affected' = case-control."},
/*72*/ {"q":"Cross Sectional Study: Disease and Risk Factors studied simultaneously. Which of the following is a direct consequence of malfunction of the Na+/K+ pump in cells?","o":["Increased intracellular potassium","Decreased intracellular sodium","Increased intracellular calcium","Hyperpolarization of cell membrane"],"a":2,"e":"The Na+/K+ ATPase maintains low intracellular Na+ and low intracellular Ca2+ (indirectly via the Na+-Ca2+ exchanger, which uses the Na+ gradient to extrude Ca2+). When the pump fails, intracellular Na+ rises, reducing the driving force for the Na+-Ca2+ exchanger, causing intracellular Ca2+ to accumulate — triggering cell injury.<br><br>Key discriminator: Na+/K+ pump fails → intracellular Na+ rises → Na+-Ca2+ exchanger reverses → intracellular Ca2+ rises → cell death | Elevated intracellular Ca2+ → activates proteases, phospholipases, endonucleases."},
/*73*/ {"q":"Chorionic villus sampling done at which week?","o":["10 week","11 week","15 week","20 week"],"a":1,"e":"Chorionic villus sampling (CVS) is performed between 10 and 13 weeks of gestation (most commonly at 11-13 weeks). It allows earlier prenatal diagnosis of chromosomal and genetic disorders compared to amniocentesis (performed at 15-20 weeks).<br><br>Key discriminator: CVS → 10-13 weeks (1st trimester, earlier diagnosis) | Amniocentesis → 15-20 weeks (2nd trimester) | CVS miscarriage risk → ~1% (higher than amniocentesis ~0.5%) | 11 weeks = classic CVS timing."},
/*74*/ {"q":"Which of the following is most important in doctor-patient relationship?","o":["Mutual trust","Mutual respect","Clarity","Confidence"],"a":0,"e":"Mutual trust is the cornerstone of the doctor-patient relationship. It encompasses honesty, confidentiality, competence, and patient autonomy. Trust enables patients to disclose sensitive information and comply with treatment plans, and is foundational to therapeutic communication.<br><br>Key discriminator: Doctor-patient relationship → mutual trust is the foundation | Trust enables → disclosure, compliance, therapeutic communication | Respect/clarity/confidence → all important but secondary to trust."},
/*75*/ {"q":"Translocation of lymphoma is seen in Burkitt's:","o":["t(8:21)","t(9:22)","t(11:14)","t(8:14)"],"a":3,"e":"Burkitt lymphoma is characterized by the t(8;14) translocation, which juxtaposes the MYC oncogene on chromosome 8 with the immunoglobulin heavy chain locus on chromosome 14, causing MYC overexpression and uncontrolled B-cell proliferation. Variants involve t(2;8) and t(8;22).<br><br>Key discriminator: Burkitt lymphoma → t(8;14): MYC + IgH locus | t(9;22) → CML (Philadelphia chromosome, BCR-ABL) | t(8;21) → AML M2 | t(11;14) → Mantle cell lymphoma."},
/*76*/ {"q":"Patient with pulsatile abdominal mass, decreased peripheral pulsation, abdominal pain for 20 years. Most likely diagnosis:","o":["Superior vena cava aneurysm","Rupture of IVC","Abdominal aortic aneurysm","Thoracic aortic aneurysm"],"a":2,"e":"An elderly patient with a pulsatile abdominal mass, peripheral vascular disease, and long history fits abdominal aortic aneurysm (AAA). AAA presents as a pulsatile epigastric/periumbilical mass and is associated with atherosclerosis, hypertension, and male sex over 65.<br><br>Key discriminator: Pulsatile abdominal mass + vascular risk factors + long history → AAA until proven otherwise | Rupture → sudden back pain + hypotension + pulsatile mass | Stable chronic AAA = this question's scenario."},
/*77*/ {"q":"A known old patient presents with haematemesis resulting from:","o":["Bleeding","Haematemesis","Superior vena Cava rupture","Rupture of IVC"],"a":0,"e":"Haematemesis (vomiting blood) results from upper gastrointestinal bleeding — sources include peptic ulcer disease, esophageal varices, Mallory-Weiss tear, or gastric erosions. In a known patient with liver disease or portal hypertension, bleeding esophageal varices are the most likely cause.<br><br>Key discriminator: Haematemesis → upper GI bleeding (proximal to ligament of Treitz) | Most common cause → peptic ulcer | Cirrhosis/portal hypertension → oesophageal varices (life-threatening cause)."},
/*78*/ {"q":"Short term memory loss occurs due to lesion of:","o":["Right Gastric Vein","Splenic Vein","Left Gastric Artery","Hippocampus"],"a":3,"e":"The hippocampus (in the medial temporal lobe) is essential for the formation of new declarative memories (short-term to long-term memory consolidation). Bilateral hippocampal lesions — as in Alzheimer's disease, herpes encephalitis, or surgical resection — produce anterograde amnesia with preserved remote memories.<br><br>Key discriminator: Hippocampus → short-term/new memory formation (anterograde) | Amygdala → emotional memory | Cerebellum → procedural/motor memory | Frontal lobe → working memory + executive function."},
/*79*/ {"q":"Short term memory loss is due to lesion of Hippocampus while long term memory changes are due to:","o":["Frontal Lobe","Neoortex","Parahippocampal","Hippocampus"],"a":1,"e":"Long-term memories are ultimately stored in the neocortex — distributed across association areas relevant to the type of memory (visual cortex for visual memories, auditory cortex for auditory, etc.). The hippocampus consolidates and transfers memories to the neocortex but is not the final storage site.<br><br>Key discriminator: Hippocampus → consolidation and transfer of memories | Neocortex → long-term storage (distributed) | Hippocampal lesion → lose new memory but retain remote (neocortically stored) memories."},
/*80*/ {"q":"Maximum ventricular filling in:","o":["Middle 3rd of diastole","Last third of diastole","1st third of diastole","Isovolumetric relaxation"],"a":2,"e":"Most ventricular filling (approximately 70-80%) occurs during the first third of diastole (rapid filling phase), immediately after the AV valves open and the pressure gradient between atria and ventricles is greatest. The remaining filling occurs during mid-diastole (diastasis) and the atrial kick (last third).<br><br>Key discriminator: 1st third of diastole → rapid filling (70-80% of ventricular volume, maximum) | Middle third → slow filling/diastasis (minimal) | Last third → atrial kick (+20-30%) | S3 generated during rapid filling phase."},
/*81*/ {"q":"Artery present at the base of pyramids:","o":["Arcuate artery","Interlobular artery","Lobar artery","Segmental artery"],"a":0,"e":"The arcuate arteries run along the corticomedullary junction at the base of the renal pyramids. They are branches of the interlobar arteries and give rise to the interlobular (cortical radiate) arteries that ascend into the cortex to supply the glomeruli.<br><br>Key discriminator: Renal arterial sequence (hilum inward): Segmental → Interlobar → Arcuate (base of pyramids) → Interlobular → Afferent arterioles | Arcuate = corticomedullary junction level."},
/*82*/ {"q":"Chorionic villus sampling done at which week?","o":["11 week","13 week","15 week","20 week"],"a":0,"e":"Chorionic villus sampling (CVS) is optimally performed between 10 and 13 weeks of gestation, with 11 weeks being the most cited timing. It allows first-trimester prenatal diagnosis of chromosomal abnormalities, avoiding the longer wait for amniocentesis.<br><br>Key discriminator: CVS → 10-13 weeks | Amniocentesis → 15-20 weeks | Earlier diagnosis = CVS advantage | Higher miscarriage risk (~1% CVS vs ~0.5% amniocentesis) = CVS trade-off."},
/*83*/ {"q":"Amniocentesis at 15 weeks and 1% risk of miscarriage. 5% risk of miscarriage and Cordocentesis at 20 weeks and 2% risk of miscarriage. Staphylococcus aureus bacteria:","o":["Sarcoidosis","Streptococcus","Actinomycetes","Listeria"],"a":0,"e":"Staphylococcus aureus produces catalase and coagulase, is gram-positive, and is associated with granuloma-forming conditions in some contexts. However, the question matches Staphylococcus aureus to its characteristic tissue response — it forms abscesses with liquefactive necrosis, contrasting with the caseating granulomas of Sarcoidosis which contain epithelioid and giant cells (non-caseating).<br><br>Key discriminator: Non-caseating granulomas + Schaumann/asteroid bodies → Sarcoidosis | Caseating granulomas → TB | Staph aureus → suppurative abscesses (liquefactive, pus-forming), NOT granulomas."},
/*84*/ {"q":"A patient was diagnosed with Hypertension and treated with big toe swelling and direct few months later patient present with hyperuricemia. Which drug is responsible?","o":["Loop diuretic","Thiazide diuretic","Aceazolamide","Propranolol"],"a":1,"e":"Thiazide diuretics cause hyperuricemia by competitively inhibiting uric acid secretion in the proximal tubule and by increasing uric acid reabsorption (secondary to volume depletion). This can precipitate gout — presenting as big toe swelling (podagra).<br><br>Key discriminator: Thiazide diuretics → hyperuricaemia + gout (inhibit uric acid secretion in PCT) | Loop diuretics → also cause hyperuricaemia but less classically | Beta-blockers/ACEi → do NOT cause hyperuricaemia."},
/*85*/ {"q":"Injury to greater wing of sphenoid and inferior orbital fissure causes damage to which nerve?","o":["Oculomotor","Trochlear","Zygomatic","Nasociliary"],"a":2,"e":"The inferior orbital fissure transmits the zygomatic nerve (branch of maxillary V2), the infraorbital nerve, branches of the pterygopalatine ganglion, and the inferior ophthalmic vein. Injury to the greater wing of sphenoid affecting the inferior orbital fissure damages the zygomatic nerve primarily.<br><br>Key discriminator: Superior orbital fissure → CN III, IV, V1 (ophthalmic), VI | Inferior orbital fissure → V2 branches (zygomatic, infraorbital) | Fissure level determines which CN division is at risk."},
/*86*/ {"q":"Patient had cough and X-ray shows non-caseating granulomas and lymphadenopathy. Diagnosis is:","o":["Sarcoidosis","Nasocillary","Trochlear","Zygomatic"],"a":0,"e":"Non-caseating granulomas on biopsy combined with bilateral hilar lymphadenopathy on chest X-ray is the classic presentation of sarcoidosis. The granulomas contain epithelioid cells and Langhans-type giant cells without central caseation, distinguishing sarcoidosis from tuberculosis.<br><br>Key discriminator: Non-caseating granulomas + bilateral hilar lymphadenopathy → Sarcoidosis | Caseating granulomas → TB | Schaumann + asteroid bodies in giant cells → further confirm sarcoidosis."},
/*87*/ {"q":"On histology, shows flask-shaped dendrite synapse cells, multiple dendritic synapse in Substantia nigra:","o":["A (Robin)","Leprosy","TB","Syphilis"],"a":0,"e":"Robin (A Robin) cells — more precisely, Lewy bodies within dopaminergic neurons of the substantia nigra — are the histological hallmark of Parkinson's disease. However, the description of flask-shaped cells with multiple dendritic synapses in the substantia nigra classically describes Purkinje cells of the cerebellum or substantia nigra neurons. The 'A Robin' designation here refers to the histological cell type described.<br><br>Key discriminator: Substantia nigra → large dopaminergic neurons with extensive dendritic trees (flask-shaped) | Loss in Parkinson's → characteristic flask-shaped neuronal remnants | Distinguishes SN histology from cortical/cerebellar cells."},
/*88*/ {"q":"Acute phase proteins is:","o":["Ceruloplasmin","Globulin","C Reactive protein","Ferritin"],"a":2,"e":"C-reactive protein (CRP) is the prototypical acute phase reactant, rising sharply within 6-8 hours of tissue injury, infection, or inflammation. It is synthesized by the liver in response to IL-6. Other positive acute phase reactants include fibrinogen, ferritin, and ceruloplasmin.<br><br>Key discriminator: CRP → most sensitive + rapidly rising acute phase protein (rises within 6-8 hrs) | Albumin + transferrin → NEGATIVE acute phase reactants (they fall) | CRP = standard clinical marker of acute inflammation."},
/*89*/ {"q":"Neurophysiologist is unable to generate action potential due to stimulating a nerve. Negative:","o":["Albumin","Transferrin","Iron","Ferritin"],"a":0,"e":"Albumin is a negative acute phase reactant — its serum level falls during acute inflammation as hepatic protein synthesis shifts toward producing positive acute phase proteins (CRP, fibrinogen, ferritin). Low albumin in acute illness reflects this hepatic prioritization, not necessarily nutritional deficiency.<br><br>Key discriminator: Positive APR (rise) → CRP, fibrinogen, ferritin, ceruloplasmin, haptoglobin | Negative APR (fall) → albumin, transferrin, prealbumin | Albumin = classic negative acute phase reactant."},
/*90*/ {"q":"At which vertebral level does the renal artery typically enter the kidney?","o":["Hypokalemia","Hyperkalemia","Hyponatraemia","Hypokalaemia"],"a":1,"e":"The renal arteries arise from the aorta at the L1-L2 vertebral level, with the right renal artery passing posterior to the IVC. Hyperkalemia is the electrolyte imbalance most directly regulated by the kidney via aldosterone-mediated potassium secretion in the collecting duct.<br><br>Key discriminator: Kidney → primary regulator of potassium via aldosterone-driven K+ secretion in collecting duct | Hyperkalemia → stimulates aldosterone → increases K+ excretion | Renal artery → enters at L1-L2."},
/*91*/ {"q":"TRALI occurs in:","o":["T10","L2","L3","L4"],"a":1,"e":"Transfusion-related acute lung injury (TRALI) occurs within 6 hours of blood transfusion, caused by donor antibodies (anti-HLA or anti-neutrophil) activating recipient neutrophils in the pulmonary vasculature, causing non-cardiogenic pulmonary edema. It is the leading cause of transfusion-related mortality.<br><br>Key discriminator: TRALI → within 6 hrs of transfusion + non-cardiogenic pulmonary oedema + fever + hypotension | TACO → cardiogenic pulmonary oedema (fluid overload) | 6-hr window + non-cardiogenic = TRALI vs TACO."},
/*92*/ {"q":"What structure is notably absent in the cervical spinal cord when compared to the thoracic and lumbar spinal cord?","o":["Posterior horn","Anterior horn","Lateral horn","Dorsal root ganglion"],"a":2,"e":"The lateral horn (intermediolateral cell column) contains preganglionic sympathetic neurons and is present only in the thoracic (T1-L2) and upper lumbar spinal cord segments. It is absent in the cervical and sacral cord. The cervical cord therefore lacks a lateral horn.<br><br>Key discriminator: Lateral horn → sympathetic preganglionic neurons, present only T1-L2 | Absent in cervical + sacral cord | Anterior horn → motor (all levels) | Posterior horn → sensory relay (all levels)."},
/*93*/ {"q":"Respiratory zone where gaseous exchange occurs beyond terminal bronchioles:","o":["Terminal bronchioles","Respiratory bronchioles","Alveolar ducts","Alveoli only"],"a":1,"e":"The respiratory zone begins at the respiratory bronchioles, which have alveoli opening directly into their walls. Gas exchange occurs from the respiratory bronchioles through the alveolar ducts to the alveoli. Terminal bronchioles are the last purely conducting airways with no gas exchange.<br><br>Key discriminator: Conducting zone ends → terminal bronchioles (anatomical dead space) | Respiratory zone begins → respiratory bronchioles (alveoli appear in walls) | Terminal → respiratory bronchiole junction = the key transition."},
/*94*/ {"q":"A 12-year-old child presented with hepatosplenomegaly, blood counts showed decreased platelets, blood count decreased. Which of the following investigation should be done?","o":["Urine culture","Blood Culture","Stool Culture","Biopsy of Marrow"],"a":3,"e":"Hepatosplenomegaly with pancytopenia (decreased platelets, decreased blood counts) in a child suggests bone marrow infiltration or failure — leukemia, lymphoma, or storage disorders (e.g., Gaucher's). Bone marrow biopsy is the definitive investigation to identify the underlying pathology.<br><br>Key discriminator: Pancytopenia + organomegaly in a child → bone marrow biopsy first | Cultures → for infection, do not explain pancytopenia | Bone marrow biopsy → directly visualises marrow failure or infiltration."},
/*95*/ {"q":"Which muscle results in vocal cord abducted position?","o":["Thyroarytenoid","Posterior cricoarytenoid","Lateral cricoarytenoid","Vocalis"],"a":1,"e":"The posterior cricoarytenoid (PCA) is the only intrinsic laryngeal muscle that abducts the vocal cords, rotating the arytenoid cartilages laterally to open the glottis for breathing. Bilateral PCA paralysis causes life-threatening airway obstruction as both cords fall to the midline.<br><br>Key discriminator: PCA (posterior cricoarytenoid) → only abductor of vocal cords | Lateral cricoarytenoid → adductor | Thyroarytenoid → tenses/shortens cord | Cricothyroid → tenses/lengthens cord | PCA = the only opener."},
/*96*/ {"q":"Flexor at hip and knee joint:","o":["Sartorius","Flexor at hip and knee — Sartorius","Smith fracture","Bennett fracture"],"a":0,"e":"The sartorius muscle is the longest muscle in the body, crossing both the hip and knee joints. It flexes, abducts, and laterally rotates the hip, and flexes the knee. It is the primary biarticular flexor active at both joints simultaneously.<br><br>Key discriminator: Sartorius → flexes both hip AND knee (biarticular) | Rectus femoris → flexes hip + extends knee | Iliopsoas → hip only | Sartorius = the only biarticular muscle that flexes both hip and knee."},
/*97*/ {"q":"A artery of Adamkiewicz arises at level of:","o":["T7 to T12","T9 to T12","T6 to T12","T12-L2"],"a":1,"e":"The artery of Adamkiewicz (arteria radicularis magna) is the dominant blood supply to the lower two-thirds of the spinal cord. It typically arises between T9 and T12, most commonly at T10 on the left side. Its injury during thoracic aortic surgery can cause anterior spinal artery syndrome.<br><br>Key discriminator: Artery of Adamkiewicz → T9-T12 (most commonly T10, left side) | Occlusion → anterior cord syndrome (motor loss + pain/temperature loss below, posterior column preserved) | T9-T12 = range to memorise."},
/*98*/ {"q":"An old man presented with urinary symptoms. Doctor made a diagnosis of benign prostatic hypertrophy (BPH). Which zone of prostate is involved in this condition?","o":["T1-T2","T7 to T12","T6 to T12","T9 to T12"],"a":0,"e":"BPH arises from the transition zone of the prostate, which surrounds the urethra. Enlargement of the transition zone compresses the urethra, causing obstructive urinary symptoms (hesitancy, poor stream, retention). Prostate cancer, in contrast, arises most commonly from the peripheral zone.<br><br>Key discriminator: BPH → transition zone (periurethral → compresses urethra → obstructive symptoms) | Prostate cancer → peripheral zone (palpable on DRE, detected by PSA) | Zone = determines pathology + presentation."},
/*99*/ {"q":"For protein metabolism which vitamin is necessary?","o":["Riboflavin","Thiamine","Biotin","Pantothenic acid"],"a":0,"e":"Riboflavin (Vitamin B2) is essential for protein metabolism as a component of FMN and FAD coenzymes involved in oxidative metabolism of amino acids. FAD-dependent amino acid oxidases catalyze deamination reactions central to protein catabolism.<br><br>Key discriminator: Thiamine (B1) → carbohydrate metabolism (pyruvate dehydrogenase) | Riboflavin (B2) → protein + fat metabolism (FAD/FMN) | Biotin → carboxylation reactions | Pyridoxine (B6) → primary amino acid metabolism."},
/*100*/ {"q":"For Carbohydrate — Thiamine, For Lipid — Riboflavin, For Protein — Riboflavin. Chaga's disease and congenital disease affects which layer?","o":["Mucosa","Submucosa","Serosa","Muscularis externa"],"a":1,"e":"Chagas disease (Trypanosoma cruzi) destroys the myenteric (Auerbach's) plexus located in the submucosa/muscularis layers of the gut wall, causing loss of coordinated peristalsis and mega-syndromes (megaesophagus, megacolon). The submucosal plexus (Meissner's) is also affected.<br><br>Key discriminator: Chagas disease → destroys myenteric plexus (submucosa/muscularis) | Result → megaesophagus + megacolon (achalasia-like) | NOT mucosa or serosa | T. cruzi = Chagas; distinguishes from other GI dysmotility."}
,
/*101*/ {"q":"A patient of mitral stenosis having dysphagia by compressing on esophagus. Which of the following structure causes dysphagia by compressing on the esophagus?","o":["Left atrium","Left bronchus","Aortic arch","Right ventricle"],"a":0,"e":"The left atrium lies directly anterior to the esophagus. In mitral stenosis, the left atrium dilates markedly due to chronically elevated left atrial pressure. This enlarged left atrium compresses the esophagus posteriorly, causing dysphagia — detectable on barium swallow as posterior esophageal indentation.<br><br>Key discriminator: Left atrium → only cardiac chamber directly posterior to oesophagus | Dilated LA (mitral stenosis) → compresses oesophagus → dysphagia | Aortic arch → indents higher up | Dilated LA + dysphagia = classic mitral stenosis sign."},
/*102*/ {"q":"RBC is kept in hypertonic solution containing Urea, what will be the result?","o":["Swell and lyse","Swell and not lyse","Shrink","Shrink and lyse"],"a":1,"e":"Urea is a penetrating solute — it freely crosses the RBC membrane. When RBCs are placed in hypertonic urea solution, water initially leaves (cell shrinks) but urea rapidly enters the cell. As intracellular urea equilibrates, osmotic balance is restored and water re-enters, causing the cell to swell. However, since urea is penetrating and equilibrates, the cell does not lyse as it would with non-penetrating solutes.<br><br>Key discriminator: Urea → penetrating solute (crosses RBC membrane freely) | Hypertonic urea → initial shrink → urea enters → osmotic equilibrium restored → cell re-swells | Cell swells but does NOT lyse (unlike non-penetrating solutes)."},
/*103*/ {"q":"A doctor saw a mass on mammography but could not palpate it. Where could it be located?","o":["Deep pectoral fascia","Axilla","Skin","Right atrium"],"a":0,"e":"Non-palpable mammographic lesions are typically located deep in the breast, behind the deep pectoral fascia or close to the chest wall. Mammography can detect lesions as small as 2-3 mm that are obscured by surrounding breast tissue from clinical palpation. Deep pectoral fascia location makes the mass inaccessible to physical examination.<br><br>Key discriminator: Non-palpable mammographic lesion → located deep (behind deep pectoral fascia / chest wall) | Axillary tail/skin lesions → palpable | Mammography → detects lesions <3mm before palpable = rationale for screening."},
/*104*/ {"q":"Dissociation curve is caused by: Right shift of oxygen dissociation curve is caused by:","o":["Increase PH","Decrease PH","Decrease PCO2","Decrease H ions"],"a":1,"e":"The oxygen-hemoglobin dissociation curve shifts right (decreased O2 affinity, increased O2 delivery to tissues) with: decreased pH (Bohr effect), increased PCO2, increased temperature, increased 2,3-DPG. Decreased pH (increased H+) is the classic Bohr effect trigger during exercise and tissue hypoxia.<br><br>Key discriminator: Right shift of O2 dissociation curve → decreased O2 affinity → better tissue delivery | Caused by: ↓pH, ↑PCO2, ↑temperature, ↑2,3-DPG | Memory: CADET face Right (CO2, Acid, DPG, Exercise, Temperature)."},
/*105*/ {"q":"Causes of decrease CO2: Alpha adrenergic stimulation:","o":["Increase activity of gut","Vasoconstriction","Bronchodilation","Pupillary dilation"],"a":1,"e":"Alpha-1 adrenergic receptor stimulation causes vasoconstriction of peripheral blood vessels (skin, viscera, mucosae) via IP3/Ca2+ signaling in vascular smooth muscle. This is the dominant vascular effect of norepinephrine and high-dose epinephrine.<br><br>Key discriminator: Alpha-1 stimulation → vasoconstriction (IP3/Ca2+ pathway) | Beta-2 → bronchodilation + vasodilation in skeletal muscle | Beta-1 → ↑HR + ↑contractility | Alpha-2 → presynaptic NE inhibition."},
/*106*/ {"q":"Rh agglutinin is present on RBC surface:","o":["Glycoproteins in RH+ blood grps","Always present in serum","RH- individual has D antigen","Contract ciliary muscle (Near vision)"],"a":0,"e":"Rh antigens (especially the D antigen) are glycoproteins embedded in the RBC membrane of Rh-positive individuals. Rh-negative individuals lack the D antigen on their RBC surface. Anti-D antibodies (Rh agglutinins) are NOT naturally occurring — they only develop after sensitization by transfusion or pregnancy.<br><br>Key discriminator: Rh D antigen → glycoprotein on RBC surface of Rh+ individuals | ABO antibodies → naturally occurring (no prior exposure needed) | Rh anti-D → immune/acquired (requires sensitisation by transfusion or pregnancy)."},
/*107*/ {"q":"A patient presented with keratitis, xerostomia and joint pain. Most likely suffering from:","o":["Wegner Granulomatosis","Rheumatoid Arthritis","SLE","Sjogren Syndrome"],"a":3,"e":"Sjogren syndrome is an autoimmune disorder targeting exocrine glands, causing keratoconjunctivitis sicca (dry eyes with keratitis) and xerostomia (dry mouth). Joint pain (arthritis) is a common systemic feature. Anti-Ro/SSA and anti-La/SSB antibodies are characteristic.<br><br>Key discriminator: Sjogren → dry eyes (keratitis) + dry mouth + arthritis = sicca syndrome | Wegener (GPA) → upper/lower respiratory + renal disease | SLE → malar rash + ANA + multi-system | Sicca syndrome = Sjogren."},
/*108*/ {"q":"Thoracic duct terminates at:","o":["Junction of internal jugular and left subclavian","Right internal jugular vein","Superior vena cava","Right brachiocephalic vein"],"a":0,"e":"The thoracic duct (the largest lymphatic vessel, draining lymph from below the diaphragm and the left side of the body above) empties into the venous system at the junction of the left internal jugular vein and left subclavian vein (left venous angle/jugulosubclavian junction).<br><br>Key discriminator: Thoracic duct → terminates at left venous angle (left IJV + left subclavian junction) | Right lymphatic duct → right venous angle | Thoracic duct = final common lymphatic pathway for most of the body."},
/*109*/ {"q":"Thoracic duct empties into: Origin of left brachiocephalic vein — Venous system near union of left:","o":["Right subclavian vein","Superior vena cava","Right internal jugular vein","Internal jugular vein and left subclavian vein"],"a":3,"e":"The left brachiocephalic vein is formed by the union of the left internal jugular vein and left subclavian vein, at the root of the neck behind the left sternoclavicular joint. It then crosses the midline to join the right brachiocephalic vein forming the superior vena cava.<br><br>Key discriminator: Left brachiocephalic vein → formed by union of left IJV + left subclavian | Right brachiocephalic → right IJV + right subclavian | Both → join to form SVC | Thoracic duct also empties at the left venous angle."},
/*110*/ {"q":"Oxygen organ utilizes 70% of its arterial supply at:","o":["Liver","Brain","A beta","A delta fibers"],"a":1,"e":"The brain (heart also uses ~70%) extracts approximately 70% of the oxygen from arterial blood — the highest oxygen extraction ratio of any organ at rest. This near-maximal baseline extraction means the brain can only increase oxygen delivery by increasing blood flow (no reserve for increased extraction).<br><br>Key discriminator: Brain → extracts ~70% O2 at rest (highest extraction ratio) | Cannot increase extraction further → relies solely on increased blood flow when demand rises | Any flow reduction → immediate hypoxia."},
/*111*/ {"q":"Which fiber sensation lost first after administration of local anesthetic?","o":["A beta","B fibers","C fibers","A delta fibers"],"a":2,"e":"Small unmyelinated C fibers (pain and temperature) are blocked first by local anesthetics because they have a small diameter and lack myelin, requiring less anesthetic to achieve blockade. The sequence of loss is: pain (C fibers) → temperature → touch → pressure → motor (A-alpha last).<br><br>Key discriminator: Local anaesthetic block order (smallest/unmyelinated first): C fibres (pain) → A-delta (temperature) → A-beta (touch) → A-alpha (motor) | Pain lost first, motor last."},
/*112*/ {"q":"The most common ectopic pregnancy is:","o":["L5","L2","L1-L1","L1-L4"],"a":1,"e":"The most common site of ectopic pregnancy is the ampulla of the fallopian tube (L2 vertebral level is not relevant here — the question stem conflates two topics). The ampullary region accounts for approximately 70% of all ectopic pregnancies, followed by the isthmus and fimbrial end.<br><br>Key discriminator: Ectopic pregnancy sites: Ampulla → 70% (most common) | Isthmus → ruptures earliest (narrow lumen) | Interstitial/cornual → rarest but most dangerous | Ampulla = most common ectopic site."},
/*113*/ {"q":"Cranial neuropore closure defect with absent brain calvarium is:","o":["Cervix","Fallopian tubes","Greater omentum","Hydrocephalus"],"a":3,"e":"Failure of the anterior neuropore to close results in anencephaly — absence of the forebrain and calvarium (skull vault). The cranial neuropore normally closes by day 25 of embryonic development. Failure leads to exposure and degeneration of neural tissue, resulting in the characteristic absent calvarium with exposed neural tissue.<br><br>Key discriminator: Anterior neuropore failure (day 25) → anencephaly (absent calvarium + forebrain) | Posterior neuropore failure → spina bifida | Hydrocephalus → CSF obstruction, NOT neuropore failure."},
/*114*/ {"q":"A female presented with intense feeling of heat (hyperthermia) and her eyes were bulging (exophthalmos) and outside feeling. Diagnosis of Grave's Disease made. Which of the following associated with loss of sensation:","o":["Mandibular fracture","Melocclusion","Anencephaly","Boxer"],"a":0,"e":"Mandibular fractures can damage the inferior alveolar nerve (branch of V3/mandibular), causing loss of sensation over the lower teeth, gums, lip, and chin (mental nerve distribution). The question pairs Graves disease with a unrelated anatomy question about mandibular nerve injury in fracture.<br><br>Key discriminator: Mandibular fracture → damages inferior alveolar nerve (runs in mandibular canal) | Result → loss of sensation: lower teeth, gum, lip, chin (mental nerve distribution) | Jaw trauma + lower lip numbness = inferior alveolar nerve injury."},
/*115*/ {"q":"A female presented with intense feeling of heat and bulging eyes. Loss of sensation outside and her eyes were bulging (exophthalmos). Diagnosis:","o":["Loss of sensation over lower teeth","Loss of taste to 2/3 of tongue","Mylohyoid muscle unable to stabilize","Mandibular fracture just before the mandibular foramen will"],"a":3,"e":"Graves disease (autoimmune hyperthyroidism) causes exophthalmos (proptosis) due to TSH-receptor antibody stimulation of orbital fibroblasts producing glycosaminoglycans, pushing the globe forward. Hyperthermia results from elevated metabolic rate. A mandibular fracture proximal to the mandibular foramen interrupts the inferior alveolar nerve before it enters the canal.<br><br>Key discriminator: Graves disease exophthalmos → orbital glycosaminoglycan deposition (TSH-receptor Ab stimulates orbital fibroblasts) | NOT fat herniation | Only hyperthyroid condition causing proptosis → toxic multinodular goiter does NOT."},
/*116*/ {"q":"In a female presented with dysphagia to liquid for last 6 months. Laryngoscopy shows normal. Which of the following is the most likely cause?","o":["Increase HR","Cold intolerance","Decrease O2 Consumption","Decrease HR"],"a":3,"e":"Dysphagia to liquids (more than solids) in the context of normal laryngoscopy suggests a neuromuscular cause rather than a mechanical obstruction. Decreased heart rate (bradycardia) in the context of hypothyroidism — which also causes cold intolerance and decreased O2 consumption — can be associated with dysphagia from hypopharyngeal motor dysfunction.<br><br>Key discriminator: Dysphagia to liquids > solids → neuromuscular cause (achalasia, MG, CN IX/X palsy) | Dysphagia to solids > liquids → mechanical obstruction (stricture, cancer) | Normal laryngoscopy → structural lesion excluded."},
/*117*/ {"q":"A patient presented with keratitis, xerostomia, and joint pain. Sjogren syndrome is characterized by:","o":["Absence of lacrimal secretion","Sjogren Syndrome","Rheumatoid Arthritis","Wegner Granulomatosis"],"a":0,"e":"Sjogren syndrome is an autoimmune exocrinopathy causing destruction of salivary and lacrimal glands by lymphocytic infiltration. Absence of lacrimal secretion (aqueous-deficient dry eye) leads to keratoconjunctivitis sicca. The Schirmer test (less than 5mm wetting) confirms absent lacrimal secretion.<br><br>Key discriminator: Sjogren → absent lacrimal secretion (Schirmer test <5mm) + absent salivary secretion + anti-Ro/SSA + anti-La/SSB | Primary Sjogren → no underlying disease | Secondary Sjogren → with RA or SLE."},
/*118*/ {"q":"Which of the following cells are found in parasitic infection?","o":["B lymphocytes 20%","T lymphocytes 10%","B lymphocytes 80-90% and T","Eosinophils"],"a":3,"e":"Eosinophils are the characteristic cells elevated in parasitic (especially helminthic) infections and allergic conditions. They contain major basic protein and eosinophil cationic protein that are toxic to parasites. Eosinophilia (elevated eosinophil count) in the peripheral blood is the hallmark of tissue-invasive helminth infections.<br><br>Key discriminator: Eosinophilia → helminthic (tissue-invasive) parasites + allergies | Neutrophilia → bacterial infections | Lymphocytosis → viral infections | Mnemonic: NAACP (Neoplasm, Asthma, Allergy, Collagen, Parasites)."},
/*119*/ {"q":"Cardiac output in heavy exercise is augmented by:","o":["Basophils","Mast Cells","Sympathetic stimulation","Eosinophils"],"a":2,"e":"During heavy exercise, cardiac output increases from ~5 L/min to 20-25 L/min in trained athletes. This is primarily driven by sympathetic stimulation — increased heart rate (chronotropy) and contractility (inotropy) via beta-1 receptor activation. Local metabolic vasodilation in skeletal muscle reduces afterload, further augmenting output.<br><br>Key discriminator: Heavy exercise → cardiac output increased by sympathetic stimulation (beta-1: ↑HR + ↑contractility) | Local metabolic vasodilation → reduces afterload | Frank-Starling (muscle pump preload) → also contributes."},
/*120*/ {"q":"On microscopy of lymph node, diagnosis of TB with caseating granulomas found. On biopsy specimen, granulomas found for diagnosis of TB. What should be looked for?","o":["Dilation of venous vessels","Constriction of venous vessels","Increase in ventricular contractility","Langerhans giant cells"],"a":3,"e":"In TB lymphadenitis, caseating granulomas contain Langhans-type giant cells (not Langerhans cells of the skin) formed by fusion of epithelioid macrophages. These multinucleated giant cells with peripherally arranged nuclei (horseshoe pattern) are characteristic of TB granulomas and help confirm the diagnosis.<br><br>Key discriminator: Langhans giant cells → peripherally arranged nuclei (horseshoe pattern) = TB + fungal granulomas | Foreign body giant cells → random nuclear arrangement | Touton giant cells → wreath of nuclei + foamy cytoplasm (fat necrosis)."},
/*121*/ {"q":"Which part of pancreatic duct drains:","o":["Head","Neck","Body","Tail"],"a":2,"e":"The accessory pancreatic duct (duct of Santorini) drains primarily the head of the pancreas and opens into the duodenum at the minor duodenal papilla. The main pancreatic duct (duct of Wirsung) drains the body and tail, joining the CBD at the major duodenal papilla (ampulla of Vater).<br><br>Key discriminator: Accessory pancreatic duct (Santorini) → drains head → minor duodenal papilla | Main pancreatic duct (Wirsung) → drains body + tail → major papilla (ampulla of Vater) | Obstruction location → determines which duct affected."},
/*122*/ {"q":"Rights and left sub phrenic space is divided by:","o":["Uncinate process","Falciform ligament","Morrison Pouch","Foramen of Winslow"],"a":1,"e":"The falciform ligament divides the subphrenic space into right and left subphrenic spaces. It is a peritoneal fold attaching the liver to the anterior abdominal wall and diaphragm, containing the ligamentum teres. Abscesses can form in either subphrenic space after abdominal surgery or peritonitis.<br><br>Key discriminator: Falciform ligament → divides subphrenic space into right and left | Morrison's pouch → hepatorenal recess (most dependent supine site) | Foramen of Winslow → entrance to lesser sac."},
/*123*/ {"q":"A patient after RTA had severe blood loss and no urine output. Blood loss and even after 3 days patient failed to have urine output. What is cause in this patient?","o":["Reversible injury","Irreversible injury","Tubular necrosis and acute","Cortical necrosis"],"a":1,"e":"Severe prolonged ischemia from major blood loss causes irreversible renal injury (acute cortical necrosis or irreversible tubular necrosis). After 3 days of no urine output (anuria) despite resuscitation, irreversible ischemic injury to the renal parenchyma has occurred, distinguishing it from reversible pre-renal azotemia which responds to fluid replacement.<br><br>Key discriminator: 3 days anuria post-trauma despite resuscitation → irreversible renal injury | Pre-renal azotemia → reversible with fluid (urine output returns quickly) | ATN → reversible over 2-3 weeks | Persistent anuria = irreversible cortical necrosis."},
/*124*/ {"q":"A 26 year male presented to you in surgical ER after penetrating injury to right lateral chest. On examination when he inspires on the left side is enhanced. What will be the most likely diagnosis?","o":["Tension","Open pneumothorax","Hemothorax","Pleurisy"],"a":1,"e":"A penetrating chest injury creating an open wound (sucking chest wound) causes an open pneumothorax. Air enters the pleural space through the wound during inspiration (rather than via the trachea), collapsing the ipsilateral lung. Mediastinal shift toward the opposite side occurs with each breath. Enhanced breath sounds on the opposite (left) side reflect compensatory hyperventilation of the unaffected lung.<br><br>Key discriminator: Open pneumothorax (sucking chest wound) → penetrating injury + air enters via wound | Tension pneumothorax → tracheal deviation away + absent breath sounds | Penetrating wound history → distinguishes open from spontaneous."},
/*125*/ {"q":"Component of neoplastic tissue on microscopy include:","o":["Stroma, Blood vessel and Endothelial cells","Inflammatory cells","Blood","Macrophages and Lymphocytes"],"a":0,"e":"Neoplastic tissue consists of two essential components: the parenchyma (tumor cells themselves) and the stroma (supportive connective tissue including blood vessels, fibroblasts, and endothelial cells). Stroma provides the vascular supply and structural scaffold without which the tumor cannot grow beyond 1-2 mm.<br><br>Key discriminator: Neoplastic tissue components: Parenchyma (tumour cells) → determines tumour type | Stroma (blood vessels + connective tissue) → supports growth via angiogenesis | VEGF → drives tumour angiogenesis (therapeutic target)."},
/*126*/ {"q":"Which anatomical structure in the human body originates from two embryonic germ layers or parts?","o":["Macrophages and Vessel","Lymphatics and Endothelial cells","Inflammatory cells and Blood","Macrophages and Lymphocytes"],"a":0,"e":"The pancreas has both endodermal and mesodermal origins: its endocrine and exocrine parenchyma derive from endoderm (foregut), while its stromal connective tissue, blood vessels, and mesenchyme derive from mesoderm. Similarly, the adrenal gland originates from two germ layers — cortex from mesoderm, medulla from neural crest (ectoderm).<br><br>Key discriminator: Adrenal gland → classic dual-origin organ: Cortex → mesoderm | Medulla → ectoderm (neural crest) | Pancreas → also dual origin: parenchyma from endoderm, stroma from mesoderm."},
/*127*/ {"q":"Lateral plate sonics development of limb is due to:","o":["Cushions","Ectodem","Lateral plate mesoderm","Somatic plate"],"a":2,"e":"The limb buds are induced and develop from the lateral plate mesoderm (somatic/parietal layer), which gives rise to the bones, cartilage, and connective tissue of the limbs. The overlying ectoderm forms the apical ectodermal ridge (AER), which drives proximal-to-distal limb outgrowth.<br><br>Key discriminator: Limb skeleton + connective tissue → lateral plate mesoderm | Muscles/vertebrae/ribs → paraxial mesoderm (somites) | AER (apical ectodermal ridge) → ectoderm, signals growth but does NOT form skeletal elements."},
/*128*/ {"q":"Lymph flow decreased by:","o":["Hemorrhage","Increased arterial pressure","Increased capillary permeability","Increased venous pressure"],"a":0,"e":"Hemorrhage decreases blood volume and arterial pressure, reducing capillary hydrostatic pressure. This decreases net fluid filtration from capillaries into the interstitium, resulting in decreased lymph formation and flow. Lymph flow is proportional to interstitial fluid accumulation, which depends on capillary filtration.<br><br>Key discriminator: Haemorrhage → reduces blood volume → reduces capillary hydrostatic pressure → less filtration → LESS lymph flow | Increased venous pressure/capillary permeability/arterial pressure → MORE lymph flow."},
/*129*/ {"q":"Patient with the deep knife wound in the buttock and walks with the waddling gait characterized by the pelvis falling to one side at each step. Which of the following nerve damaged?","o":["Common peroneal nerve","Sciatic nerve","Inferior gluteal nerve","Superior gluteal nerve"],"a":3,"e":"The superior gluteal nerve (L4, L5, S1) innervates the gluteus medius, gluteus minimus, and tensor fasciae latae. These muscles abduct the hip and stabilize the pelvis during the stance phase of gait. Injury causes a Trendelenburg gait (waddling gait with contralateral pelvic drop).<br><br>Key discriminator: Superior gluteal nerve (L4,L5,S1) → gluteus medius + minimus → hip abductors → pelvic stabilisation | Injury → Trendelenburg gait (pelvis drops to opposite side) | Inferior gluteal nerve → gluteus maximus → hip extension only."},
/*130*/ {"q":"Which of following muscle cause hip Flexion with knee extended?","o":["Rectus femoris","Gracilis","Semi membranous","Semitendinous"],"a":0,"e":"The rectus femoris is the only quadriceps muscle that crosses both the hip and knee joints. It flexes the hip and extends the knee simultaneously. When the knee is extended, the rectus femoris is the primary hip flexor, while iliopsoas also contributes.<br><br>Key discriminator: Rectus femoris → only quadriceps crossing hip AND knee: flexes hip + extends knee | Sartorius → flexes hip + flexes knee | Rectus femoris = the answer when knee is extended and hip flexed."},
/*131*/ {"q":"Loss of crude touch and pressure is due to loss of which tract?","o":["Rubrospinal tract","Corticospinal tract","Olivocerebellar tract","Dorsal column medial lemniscus"],"a":3,"e":"Crude touch, pressure, and vibration are carried by the dorsal column-medial lemniscus pathway (posterior funiculus). Fine discriminative touch, proprioception, and vibration sense are also carried here. Lesions of the dorsal columns (e.g., subacute combined degeneration, tabes dorsalis) cause loss of these modalities with preserved pain and temperature.<br><br>Key discriminator: Dorsal column lesion → ipsilateral loss of fine touch, vibration, proprioception, crude touch | Spinothalamic lesion → contralateral loss of pain + temperature | The two pathways are anatomically and functionally dissociated."},
/*132*/ {"q":"A child has history of pica now having pallor, fatigue, and low Hb. What is suitable diagnosis?","o":["B12 Deficiency","Thalassemia","Folic Acid Deficiency","Iron Deficiency Anemia"],"a":3,"e":"Pica (eating non-food items like clay, dirt, ice) is both a symptom and cause of iron deficiency anemia in children. Pallor, fatigue, and low hemoglobin in a child with pica strongly indicate iron deficiency — the most common nutritional deficiency worldwide in children.<br><br>Key discriminator: Pica + pallor + fatigue + low Hb → iron deficiency anaemia (most common nutritional deficiency in children) | Pica is both cause AND symptom of iron deficiency | Microcytic hypochromic anaemia + pica = iron deficiency until proven otherwise."},
/*133*/ {"q":"Patient head is turned to see nearby object. Which part of brain involves in this function?","o":["Superior colliculi","Inferior colliculi","Lateral geniculate","Primary visual cortex"],"a":0,"e":"The superior colliculi coordinate visual reflexes including saccadic eye movements and head-turning in response to visual stimuli. They receive direct retinal input and control reflex orienting responses — turning the head and eyes toward a visual target without conscious cortical processing.<br><br>Key discriminator: Superior colliculi → visual reflex coordination (orienting head/eyes toward visual stimulus) | Inferior colliculi → auditory reflex (orienting toward sound) | LGN + primary visual cortex → conscious visual perception."},
/*134*/ {"q":"A female presented with dysphagia to liquid for last 6 months. Laryngoscopy shows normal. Anatomy — Superior colliculus — Vision. Inferior colliculus — Auditory. Patient presented with dysphagia to liquid. Laryngoscopy shows most likely cause:","o":["Superior colliculus — Vision","Inferior colliculus — Auditory","Inferior colliculi","Glossopharyngeal nerve palsy"],"a":3,"e":"Dysphagia to liquids with normal laryngoscopy suggests a neuromuscular cause of the pharyngeal phase. Glossopharyngeal nerve (CN IX) palsy impairs the pharyngeal swallowing reflex and sensation, causing liquids to be aspirated or poorly swallowed. Normal laryngoscopy rules out structural lesions.<br><br>Key discriminator: Dysphagia to liquids > solids + normal laryngoscopy → neuromuscular/CN IX palsy | CN IX palsy → impairs pharyngeal swallowing reflex | Normal laryngoscopy → structural lesion excluded."},
/*135*/ {"q":"Hyperthyroidism occurs due to excessive thyroid hormone levels. As a result, individuals often experience weight loss, despite an increased appetite. This condition can lead to muscle wasting and a range of other symptoms associated with increased metabolic activity. Thyroid hormone levels:","o":["Increase carbohydrates absorption","Increase lipolysis","Increase oxygen requirement","Increase carbohydrate stores absorption"],"a":1,"e":"Thyroid hormones increase lipolysis by stimulating hormone-sensitive lipase and enhancing sensitivity to catecholamines, resulting in elevated free fatty acids. This, combined with increased glucose oxidation, drives the hypermetabolic state of hyperthyroidism, causing weight loss despite increased appetite.<br><br>Key discriminator: Hyperthyroidism → ↑lipolysis (fat breakdown) + ↑metabolic rate → weight loss despite increased appetite | Thyroid hormone → increases both carbohydrate and fat metabolism | Lipolysis = specific driver of weight loss."},
/*136*/ {"q":"Characteristic feature of metastasis: Up regulation of integrins:","o":["Down regulation of integrins","Up regulation of integrins","Down regulation of E-cadherins","Up regulation of E-cadherins"],"a":1,"e":"During metastasis, tumor cells upregulate integrins (cell-matrix adhesion molecules) to attach to the extracellular matrix at distant sites and establish secondary tumors. Simultaneously, E-cadherin is downregulated (epithelial-mesenchymal transition), allowing detachment from the primary tumor.<br><br>Key discriminator: Metastasis requires two opposing changes: ↓E-cadherin (leave primary tumour) AND ↑integrins (attach at new site) | Upregulation of integrins → attachment phase | Downregulation of E-cadherin → departure phase."},
/*137*/ {"q":"Patient has lost fine touch, vibration and proprioception. Where is the lesion?","o":["Anterior Spinothalamic Cortex","DCML","Anterior Cortex","Nucleus Gracilis"],"a":1,"e":"Fine discriminative touch, vibration, and proprioception are carried by the dorsal column-medial lemniscus (DCML) pathway. Lesions of the dorsal columns (posterior funiculus) produce loss of these modalities ipsilateral to the lesion, with intact pain and temperature sensation — the classic posterior column syndrome (as in B12 deficiency or tabes dorsalis).<br><br>Key discriminator: DCML lesion → ipsilateral loss of fine touch + vibration + proprioception (posterior column) | Spinothalamic lesion → contralateral loss of pain + temperature | Both pathways anatomically and functionally dissociated."},
/*138*/ {"q":"Right brachial artery arises from: Temperature and Pressure Lateral Spinothalamic — Pain and touch:","o":["Thoracic aorta at","Second right intercostal space","Second left intercostal space","Right 3rd Posterior intercostal space"],"a":1,"e":"The right bronchial artery typically arises from the right posterior intercostal artery or directly from the aorta at the level of the 2nd right intercostal space. The left bronchial arteries (usually two) arise directly from the descending thoracic aorta. Bronchial arteries supply the bronchial walls and supporting structures (not alveoli).<br><br>Key discriminator: Left bronchial arteries (×2) → arise directly from thoracic aorta | Right bronchial artery (×1) → typically from right 3rd posterior intercostal artery | Asymmetry reflects aorta's left-sided position."},
/*139*/ {"q":"Which of the following is detected by peripheral chemoreceptors?","o":["Increase P CO2","Decrease PH","5th right 3rd Posterior intercostal space","Second left intercostal space"],"a":1,"e":"Peripheral chemoreceptors (carotid and aortic bodies) primarily detect decreased arterial PO2, increased PCO2, and decreased pH (increased H+). They are the ONLY receptors that respond to hypoxia (low PO2). Central chemoreceptors detect PCO2/pH changes in CSF but cannot detect hypoxia directly.<br><br>Key discriminator: Peripheral chemoreceptors (carotid + aortic bodies) → respond to ↓PO2 (primary), ↑PCO2, ↓pH | Central chemoreceptors → respond only to PCO2/H+ in CSF, CANNOT detect hypoxia | Peripheral = only hypoxia detectors."},
/*140*/ {"q":"Vertical body symphysis have which of the following cartilage?","o":["Articular","Hyaline","A (BRS)","Fibrocartilage"],"a":3,"e":"The pubic symphysis and intervertebral disc joints (secondary cartilaginous joints/amphiarthroses) contain fibrocartilage as the connecting medium. Fibrocartilage provides tensile strength and resistance to compression, making it suitable for weight-bearing joints with limited movement.<br><br>Key discriminator: Symphysis joints → fibrocartilage (pubic symphysis, intervertebral discs, manubriosternal) | Synchondrosis → hyaline cartilage (epiphyseal plates) | 'Symphysis' designation = fibrocartilage."},
/*141*/ {"q":"During childbirth, if there is a significant decrease in anal tone, what diagnostic test can be used to assess and monitor the anal sphincter function?","o":["X-ray examination","Magnetic resonance imaging (MRI)","Anal manometry","Ultrasound imaging"],"a":2,"e":"Anal manometry is the gold standard investigation for assessing anal sphincter function. It measures resting pressure (internal sphincter) and squeeze pressure (external sphincter), identifying sphincter weakness or defects. It is used when obstetric anal sphincter injuries (OASI) are suspected after childbirth.<br><br>Key discriminator: Anal manometry → functional (measures resting + squeeze pressures) | Endoanal ultrasound → anatomical (identifies sphincter tears) | MRI → detailed structural imaging | Manometry = direct sphincter tone measurement."},
/*142*/ {"q":"During Hip Surgery vessel is ligated. Which vessel is main source of this artery head of femur?","o":["Popliteal","Internal iliac","External iliac","Femoral"],"a":1,"e":"The head of the femur is supplied predominantly by the medial circumflex femoral artery (branch of profunda femoris, itself from the femoral artery), and additionally by the artery to the ligamentum teres (obturator artery, from internal iliac). In hip surgery, ligation of these vessels causes avascular necrosis of the femoral head.<br><br>Key discriminator: Femoral head blood supply (primary) → medial circumflex femoral artery (from profunda femoris) | Disruption → AVN of femoral head (femoral neck fractures) | Artery of ligamentum teres → minor supply, from obturator (internal iliac)."},
/*143*/ {"q":"Lesion of upper eyelid mostly drained by:","o":["Superior Sagittal Sinus","Inferior Sagittal Sinus","Cavernous Sinus","Femoral"],"a":2,"e":"The upper eyelid veins drain into the superior ophthalmic vein, which drains into the cavernous sinus. This venous connection is clinically important because infections of the eyelid, orbit, or face can spread to the cavernous sinus (cavernous sinus thrombosis), causing life-threatening complications.<br><br>Key discriminator: Upper eyelid → superior ophthalmic vein → cavernous sinus | Cavernous sinus connection → periorbital infection can cause cavernous sinus thrombosis (proptosis + chemosis + CN III/IV/VI palsies)."},
/*144*/ {"q":"In a dehydrated man, ADH will cause following affect: Increase permeability through DCT:","o":["Increase Permeability through DCT","Decrease Permeability through DCT","Increase water retention through PCT","Decrease permeability following DCT"],"a":0,"e":"ADH (vasopressin) acts on V2 receptors in the principal cells of the distal convoluted tubule (DCT) and collecting duct, inserting aquaporin-2 (AQP2) water channels into the luminal membrane. This dramatically increases water permeability, allowing water reabsorption and urine concentration in dehydration.<br><br>Key discriminator: ADH (V2 receptors) → inserts AQP2 channels into DCT + collecting duct → ↑water permeability | PCT → constitutively high water permeability (independent of ADH) | ADH = regulated water conservation in DCT/collecting duct."},
/*145*/ {"q":"Wood fell down on foot between 1st and 2nd laborers. The 2nd metatarsal home. Artery most likely damaged will be:","o":["Lateral plantar","Dorsalis pedis","Medial plantar","Anterior tibial"],"a":1,"e":"The dorsalis pedis artery crosses between the 1st and 2nd metatarsals at the dorsum of the foot, giving off the first dorsal metatarsal artery and the deep plantar artery. Trauma between the 1st and 2nd metatarsals on the dorsum of the foot puts the dorsalis pedis artery at direct risk.<br><br>Key discriminator: Dorsalis pedis artery → dorsum of foot between 1st + 2nd metatarsals | Distal continuation of anterior tibial artery | Pulse palpated at dorsum of foot | Trauma between 1st and 2nd metatarsals → dorsalis pedis at risk."},
/*146*/ {"q":"Patient has pain in throat and hoarseness of voice on X-ray. Seen large styloid process:","o":["Medial plantar","Maxillary","Lingual","Ascending pharyngeal"],"a":2,"e":"Eagle syndrome results from an elongated styloid process or calcified stylohyoid ligament compressing adjacent structures. The lingual nerve and glossopharyngeal nerve pass near the styloid process. Throat pain with hoarseness suggests compression of the lingual nerve and glossopharyngeal nerve by the elongated styloid process.<br><br>Key discriminator: Eagle syndrome → elongated styloid process → compresses lingual nerve (V3) + CN IX | X-ray → large styloid process | Throat pain + hoarseness + large styloid → Eagle syndrome."},
/*147*/ {"q":"Dopamine is a prolactin inhibitory factor. If dopamine is decreased then prolactin will increase. A 55-year-old male with history of epigastric lymphoma. He developed gastric pain for which he gives many times. Most likely cause:","o":["Decrease (BRS)","Decrease Thyroxin","Increase Cortisol","Atrophic gastritis"],"a":3,"e":"In a patient with a history of lymphoma involving the epigastric region with chronic gastric pain, atrophic gastritis is the most likely underlying cause. Atrophic gastritis destroys parietal cells, reducing acid production and intrinsic factor, leading to B12 deficiency. H. pylori and autoimmune gastritis are common causes.<br><br>Key discriminator: Atrophic gastritis → destroys parietal cells → achlorhydria + intrinsic factor deficiency → B12 deficiency (pernicious anaemia) | Drug-induced → NSAIDs/aspirin | Chronic mucosal damage → can precede malignant transformation."},
/*148*/ {"q":"Hyperprolactinemia occur due to:","o":["Decrease (BRS)","Decrease Thyroxin","Increase Cortisol","Decrease dopamine"],"a":3,"e":"Prolactin secretion is tonically inhibited by dopamine from the hypothalamus. Any cause that reduces dopamine (drugs: antipsychotics, metoclopramide, methyldopa; hypothalamic lesions; stalk compression) leads to hyperprolactinemia. Primary prolactinomas also cause excess prolactin independent of dopamine.<br><br>Key discriminator: Dopamine → prolactin-inhibiting factor (tonic inhibition) | ↓Dopamine → ↑prolactin (hyperprolactinaemia) | Antipsychotics (dopamine blockers) → most common drug cause | Hypothyroidism → ↑TRH → also stimulates prolactin."},
/*149*/ {"q":"The artery which can be palpated under the mandible near the angle of jaw is:","o":["H. Pylori gastritis","Atrophic gastritis","Gastric ulcer","Facial artery"],"a":3,"e":"The facial artery is palpable where it crosses the inferior border of the mandible at the anterior edge of the masseter muscle. It is one of the reliable pulse points in the head and neck, used clinically to assess facial circulation and as a landmark in oral surgery.<br><br>Key discriminator: Facial artery → crosses inferior border of mandible at anterior edge of masseter | Palpable pulse point at mandibular body | Superficial temporal → palpable in front of tragus | Facial artery = mandibular crossing = named pulse point."},
/*150*/ {"q":"Hyperthyroidism clinical signs following:","o":["Facial","Lingual","Ascending pharyngeal","Maxillary"],"a":0,"e":"The facial artery is the vessel that supplies the face and is the one most relevant to the clinical examination context here. In hyperthyroidism, increased cardiac output and peripheral vasodilation cause bounding pulses — the facial artery pulse at the mandibular border becomes more prominent due to increased stroke volume and vasodilation.<br><br>Key discriminator: Hyperthyroidism → high-output state → bounding peripheral pulses | Facial artery at mandible → most relevant palpable facial pulse | Increased vascular pulsatility = reflection of high cardiac output."},
/*151*/ {"q":"An increased appetite, as their body utilizes stored fat for energy. With increased stored fat for energy, this can lead to muscle wasting and a range of other symptoms. The size of the drug is more than 1000, so the drug will move into cells via:","o":["Osmotic pressure","Carrier protein","Simple diffusion","Pinocytosis"],"a":3,"e":"Large molecules (molecular weight greater than 1000 daltons) that cannot pass through membrane channels or utilize carrier proteins enter cells via pinocytosis (endocytosis) — the cell membrane engulfs the molecule in a vesicle. This is the mechanism for uptake of large proteins, antibodies, and macromolecules.<br><br>Key discriminator: Drug size >1000 Da → enters cells via pinocytosis (endocytosis) | Simple diffusion → small lipophilic molecules | Carrier-mediated → medium-sized polar molecules (glucose, amino acids) | Size >1000 Da = pinocytosis trigger."},
/*152*/ {"q":"Spermatogenesis complete in:","o":["48 days","49 days","87 days","60 days"],"a":2,"e":"Complete spermatogenesis (from spermatogonium to mature spermatozoon) takes approximately 74-90 days in humans, with 87 days being the most cited figure in standard physiology. This includes spermatocytogenesis (~16 days), meiosis (~24 days), spermiogenesis (~24 days), and epididymal transit (~12 days).<br><br>Key discriminator: Spermatogenesis total time → ~87 days (74 days in seminiferous tubule + ~12 days epididymal maturation) | Chemotherapy effects on sperm → take 2-3 months to manifest and recover | 87 days = classic answer."},
/*153*/ {"q":"Which is non bleeding ulcer related to streptococcus?","o":["Meleny ulcer","Arterial ulcer","Venous ulcer","Marjolin ulcer"],"a":0,"e":"Meleney's ulcer (progressive synergistic gangrene) is caused by a synergistic infection between Streptococcus pyogenes (microaerophilic) and Staphylococcus aureus or gram-negative organisms. It is a non-bleeding, spreading progressive ulcer typically affecting the abdominal wall and is non-bleeding (no significant hemorrhage).<br><br>Key discriminator: Meleney's ulcer → streptococcal synergistic gangrene (non-bleeding, progressive spreading) | Marjolin's ulcer → SCC in chronic wound/burn scar | Venous ulcer → medial gaiter, bleeds on dressing | Meleney's = non-bleeding streptococcal ulcer."},
/*154*/ {"q":"Gastroduodenal artery found behind which of the following:","o":["4th part of duodenum","Lower body of uterus","Pancreas","Superior part of duodenum"],"a":3,"e":"The gastroduodenal artery arises from the common hepatic artery and descends behind (posterior to) the first part (superior part) of the duodenum before dividing into the right gastroepiploic artery and superior pancreaticoduodenal artery. This relationship is important in posterior duodenal ulcer erosion into the gastroduodenal artery causing massive hemorrhage.<br><br>Key discriminator: Gastroduodenal artery → lies posterior to 1st (superior) part of duodenum | Posterior duodenal ulcer → erodes through wall → hits GDA → torrential haemorrhage | GDA position = key surgical anatomy for ulcer bleeding."},
/*155*/ {"q":"4th part of duodenum drains into which lymphatics:","o":["4th part of duodenum lymphatics","Superficial inguinal LN drains","Cervix","Spleen"],"a":1,"e":"The 4th part of the duodenum and jejunum drain their lymphatics to the superior mesenteric lymph nodes. Superficial inguinal lymph nodes drain the lower limb, perineum, and external genitalia — not the duodenum. The question pairs this with asking which structure drains to superficial inguinal nodes.<br><br>Key discriminator: Superficial inguinal LN → drain: lower limb + perineum + external genitalia + lower anal canal + skin below umbilicus | Duodenal lymphatics → superior mesenteric nodes | Cervix → internal/external iliac + obturator nodes."},
/*156*/ {"q":"1st FDA approved therapy virus is:","o":["Adeno virus","Picorna virus","Paramyxo virus","Herpes simplex"],"a":0,"e":"The first FDA-approved gene therapy vector was adeno-associated virus (AAV), derived from adenovirus. Adenovirus-based vectors were among the earliest approved for gene therapy applications. Herpes simplex virus (talimogene laherparepvec, T-VEC) became the first FDA-approved oncolytic virus therapy in 2015, but the first approved therapy virus overall was adenovirus-based.<br><br>Key discriminator: Adenovirus → first FDA-approved gene therapy vector | T-VEC (HSV-based) → first approved oncolytic virus (2015) | 'First therapy virus' = adenovirus-based gene therapy (predates oncolytic approvals)."}
];
